window.MM['english_grammar']=[
{"t":"Sentence Correction","q":"Neither of the two candidates _____ selected.","a":"are","b":"was","c":"have been","d":"were","ans":"B","e":"*Neither* is singular and takes a singular verb. Therefore, *was* is correct."},
{"t":"Sentence Correction","q":"He is good _____ Mathematics.","a":"at","b":"with","c":"on","d":"in","ans":"A","e":"The standard expression is *good at* a subject, skill, or activity."},
{"t":"Conditionals","q":"If I _____ rich, I would buy a hospital.","a":"was","b":"had been","c":"were","d":"am","ans":"C","e":"In unreal present conditionals, *were* is used for all subjects."},
{"t":"Sentence Correction","q":"One of the boys _____ absent today.","a":"are","b":"were","c":"is","d":"have been","ans":"C","e":"The subject is *one*, which is singular and requires *is*."},
{"t":"Sentence Correction","q":"She has been living here _____ 2018.","a":"since","b":"for","c":"from","d":"by","ans":"A","e":"*Since* is used with a specific point in time."},
{"t":"Sentence Correction","q":"Hardly had he arrived _____ it started raining.","a":"that","b":"when","c":"than","d":"then","ans":"B","e":"The correct construction is *Hardly...when*."},
{"t":"Sentence Correction","q":"Each of the students _____ received a certificate.","a":"are","b":"were","c":"have","d":"has","ans":"D","e":"*Each* is singular and takes a singular verb."},
{"t":"Sentence Correction","q":"The patient, along with his attendants, _____ waiting outside.","a":"are","b":"is","c":"have been","d":"were","ans":"B","e":"The verb agrees with *patient*, not *attendants*."},
{"t":"Sentence Correction","q":"I prefer tea _____ coffee.","a":"to","b":"from","c":"than","d":"over","ans":"A","e":"The correct expression is *prefer A to B*."},
{"t":"Tenses","q":"By next year, she _____ her FCPS training.","a":"completes","b":"will complete","c":"will have completed","d":"completed","ans":"C","e":"Future perfect is used for an action completed before a future time."},
{"t":"Sentence Correction","q":"The news _____ surprising.","a":"were","b":"is","c":"are","d":"have been","ans":"B","e":"*News* is grammatically singular."},
{"t":"Sentence Correction","q":"He succeeded _____ convincing the committee.","a":"for","b":"on","c":"at","d":"in","ans":"D","e":"The correct phrase is *succeed in doing something*."},
{"t":"Sentence Correction","q":"No sooner had the meeting ended _____ the participants left.","a":"then","b":"when","c":"than","d":"that","ans":"C","e":"The standard construction is *No sooner...than*."},
{"t":"Subject-Verb Agreement","q":"Neither Ahmed nor his friends _____ present.","a":"was","b":"is","c":"were","d":"has been","ans":"C","e":"With *neither...nor*, the verb agrees with the nearer subject (*friends*)."},
{"t":"Modifiers & Comparisons","q":"She speaks English _____ than her sister.","a":"well","b":"better","c":"good","d":"best","ans":"B","e":"A comparison between two people requires the comparative form."},
{"t":"Prepositions","q":"The book belongs _____ me.","a":"from","b":"by","c":"to","d":"with","ans":"C","e":"The correct collocation is *belongs to*."},
{"t":"Conditionals","q":"Had he studied harder, he _____ the examination.","a":"would have passed","b":"would pass","c":"passed","d":"passes","ans":"A","e":"Third conditional sentences use *would have + past participle*."},
{"t":"Sentence Correction","q":"There _____ many reasons for the delay.","a":"are","b":"is","c":"was","d":"has been","ans":"A","e":"The real subject is *many reasons*, which is plural."},
{"t":"Modifiers & Comparisons","q":"He is the _____ intelligent student in the class.","a":"most","b":"more","c":"much","d":"very","ans":"A","e":"Superlative degree is used when comparing more than two."},
{"t":"Tenses","q":"The committee _____ its decision yesterday.","a":"announce","b":"announcing","c":"have announced","d":"announced","ans":"D","e":"A completed action in the past requires simple past tense."},
{"t":"Sentence Correction","q":"She insisted _____ paying the bill herself.","a":"on","b":"for","c":"at","d":"in","ans":"A","e":"The correct phrase is *insist on doing something*."},
{"t":"Pronouns","q":"Everybody _____ welcome to attend the seminar.","a":"are","b":"were","c":"have been","d":"is","ans":"D","e":"*Everybody* is an indefinite singular pronoun."},
{"t":"Gerunds & Infinitives","q":"The teacher asked the students _____ make noise.","a":"don't","b":"to not","c":"not to","d":"not","ans":"C","e":"The correct infinitive structure is *asked someone not to do something*."},
{"t":"Sentence Correction","q":"Scarcely had we reached the station _____ the train departed.","a":"then","b":"when","c":"than","d":"that","ans":"B","e":"The accepted construction is *Scarcely...when*."},
{"t":"Sentence Correction","q":"A number of students _____ absent today.","a":"is","b":"was","c":"has been","d":"are","ans":"D","e":"*A number of* takes a plural verb."},
{"t":"Sentence Correction","q":"The number of applicants _____ increased significantly.","a":"were","b":"are","c":"has","d":"have","ans":"C","e":"*The number of* takes a singular verb."},
{"t":"Gerunds & Infinitives","q":"He denied _____ the document.","a":"signed","b":"signing","c":"sign","d":"to sign","ans":"B","e":"*Deny* is followed by a gerund (*-ing* form)."},
{"t":"Sentence Correction","q":"She is married _____ a surgeon.","a":"by","b":"from","c":"with","d":"to","ans":"D","e":"The correct phrase is *married to*."},
{"t":"Sentence Correction","q":"The more you practice, _____ you become.","a":"better","b":"the better","c":"the best","d":"best","ans":"B","e":"The structure is *the more..., the better...*."},
{"t":"Tenses","q":"I wish I _____ the answer.","a":"knowing","b":"knew","c":"know","d":"have known","ans":"B","e":"*Wish* for a present unreal situation takes the past simple tense. **High-Yield Grammar Areas Represented (Based on FPSC Trends):** - Subject–Verb Agreement - Prepositions - Articles - Conditional Sentences - Tenses - Gerunds & Infinitives - Comparative & Superlative Forms - Indefinite Pronouns - Correlative Conjunctions (*Neither/Nor, No sooner/Than, Hardly/When*) - Common Error Detection Patterns These are among the most repeatedly tested grammar areas in FPSC one-paper examinations. **FPSC Medical Officer English Grammar MCQs (31–60)**"},
{"t":"Subject-Verb Agreement","q":"The quality of the apples _____ not good.","a":"is","b":"have been","c":"were","d":"are","ans":"A","e":"The subject is *quality*, not *apples*. Since *quality* is singular, the singular verb *is* must be used. FPSC frequently tests subject-verb agreement through such distracting plural nouns."},
{"t":"Sentence Correction","q":"He is junior _____ me in service.","a":"than","b":"to","c":"with","d":"from","ans":"B","e":"Certain adjectives such as *junior, senior, superior,* and *inferior* are followed by *to*, not *than*. This is a commonly tested grammar rule in competitive examinations."},
{"t":"Conditionals","q":"If she _____ harder, she would have secured first position.","a":"studied","b":"had studied","c":"has studied","d":"studies","ans":"B","e":"This is a third conditional sentence referring to an unreal past situation. The correct structure is *If + had + past participle*, followed by *would have + past participle*."},
{"t":"Sentence Correction","q":"The furniture _____ been delivered.","a":"have","b":"are","c":"has","d":"were","ans":"C","e":"*Furniture* is an uncountable noun and always takes a singular verb. FPSC frequently tests collective and uncountable nouns such as furniture, luggage, baggage, and equipment."},
{"t":"Prepositions","q":"He prevented me _____ entering the room.","a":"in","b":"from","c":"with","d":"at","ans":"B","e":"The correct expression is *prevent someone from doing something*. Other prepositions are grammatically incorrect with *prevent*."},
{"t":"Subject-Verb Agreement","q":"Not only the students but also the teacher _____ present.","a":"are","b":"was","c":"were","d":"have been","ans":"B","e":"In *not only...but also* constructions, the verb agrees with the subject nearest to it. Since *teacher* is singular, *was* is correct."},
{"t":"Prepositions","q":"She has little interest _____ politics.","a":"for","b":"on","c":"at","d":"in","ans":"D","e":"The standard collocation is *interest in something*. Preposition-based questions are among the most repeated grammar items in FPSC papers."},
{"t":"Tenses","q":"I would rather you _____ tomorrow.","a":"had come","b":"will come","c":"came","d":"come","ans":"C","e":"After *would rather*, when referring to another person's action, the past simple tense is used to express preference."},
{"t":"Subject-Verb Agreement","q":"Neither the manager nor the workers _____ willing to accept the proposal.","a":"was","b":"were","c":"has been","d":"is","ans":"B","e":"With *neither...nor*, the verb agrees with the subject closest to it. Here, *workers* is plural, so *were* is correct."},
{"t":"Gerunds & Infinitives","q":"The doctor advised him _____ smoking.","a":"stop","b":"to stop","c":"stopped","d":"stopping","ans":"B","e":"*Advise* is normally followed by an infinitive structure: *advise someone to do something*. This pattern is frequently tested."},
{"t":"Pronouns","q":"One should do _____ duty honestly.","a":"her","b":"his","c":"their","d":"one's","ans":"D","e":"The pronoun *one* should be followed by *one's* for formal grammatical consistency. FPSC often tests pronoun agreement."},
{"t":"Modifiers & Comparisons","q":"Hardly ever _____ such a beautiful sight.","a":"I have seen","b":"I saw","c":"did I see","d":"saw I","ans":"C","e":"Negative adverbials like *hardly ever, rarely, seldom,* and *never* often require inversion, making *did I see* the correct structure."},
{"t":"Sentence Correction","q":"The report must be submitted _____ Friday.","a":"by","b":"during","c":"since","d":"until","ans":"A","e":"*By Friday* means not later than Friday. FPSC frequently tests distinctions between *by*, *until*, *since*, and *for*."},
{"t":"Sentence Correction","q":"He behaves as if he _____ the principal.","a":"is","b":"was","c":"were","d":"has been","ans":"C","e":"In unreal comparisons introduced by *as if*, the subjunctive *were* is preferred, regardless of the subject."},
{"t":"Sentence Correction","q":"Many a student _____ failed in this test.","a":"are","b":"have","c":"has","d":"were","ans":"C","e":"Although *many a* suggests plurality in meaning, it takes a singular verb. This is a classic competitive-exam grammar rule."},
{"t":"Sentence Correction","q":"The meeting was postponed _____ the bad weather.","a":"although","b":"because","c":"since","d":"because of","ans":"D","e":"*Because of* is followed by a noun phrase (*the bad weather*), whereas *because* requires a complete clause."},
{"t":"Sentence Correction","q":"No sooner had he entered the hall _____ everyone stood up.","a":"than","b":"that","c":"then","d":"when","ans":"A","e":"The fixed grammatical construction is *No sooner...than*. This is repeatedly tested in FPSC and CSS examinations."},
{"t":"Pronouns","q":"She is one of the best teachers who _____ ever taught here.","a":"has","b":"had","c":"is","d":"have","ans":"D","e":"The relative pronoun *who* refers to *teachers* (plural), therefore the plural verb *have* is required."},
{"t":"Prepositions","q":"He is capable _____ solving the problem.","a":"to","b":"with","c":"for","d":"of","ans":"D","e":"The correct expression is *capable of doing something*. This collocation is commonly tested."},
{"t":"Prepositions","q":"I look forward to _____ from you soon.","a":"hearing","b":"have heard","c":"heard","d":"hear","ans":"A","e":"The word *to* here is a preposition, not part of an infinitive. Therefore, it must be followed by a gerund (*hearing*)."},
{"t":"Sentence Correction","q":"Every one of the players _____ given a medal.","a":"were","b":"are","c":"have been","d":"was","ans":"D","e":"*Every one* is singular and therefore requires the singular verb *was*."},
{"t":"Conditionals","q":"Had I known the truth, I _____ differently.","a":"would act","b":"acted","c":"act","d":"would have acted","ans":"D","e":"This is a third conditional sentence referring to a past unreal event. The correct result clause is *would have acted*."},
{"t":"Sentence Correction","q":"He is tired _____ working all day.","a":"with","b":"of","c":"from","d":"by","ans":"C","e":"The standard expression is *tired from doing something* when referring to the cause of fatigue."},
{"t":"Subject-Verb Agreement","q":"The accused, along with his lawyer, _____ present in court.","a":"are","b":"was","c":"have been","d":"were","ans":"B","e":"The phrase *along with his lawyer* does not affect subject-verb agreement. The verb agrees with *accused*."},
{"t":"Modifiers & Comparisons","q":"Seldom _____ such dedication among employees.","a":"we have seen","b":"we see","c":"seen we","d":"do we see","ans":"D","e":"After restrictive adverbs like *seldom*, inversion is required. Hence, *do we see* is correct."},
{"t":"Subject-Verb Agreement","q":"Neither Ali nor Ahmed _____ responsible for the error.","a":"has been","b":"are","c":"is","d":"were","ans":"C","e":"The verb agrees with the nearest subject (*Ahmed*), which is singular. Therefore, *is* is correct."},
{"t":"Sentence Correction","q":"She insisted that he _____ immediately.","a":"left","b":"leave","c":"leaves","d":"leaving","ans":"B","e":"After verbs expressing demand, insistence, or recommendation, the subjunctive form (*leave*) is used."},
{"t":"Sentence Correction","q":"The committee _____ divided in its opinion.","a":"is","b":"are","c":"were","d":"have","ans":"A","e":"In standard exam grammar, *committee* is generally treated as a singular collective noun unless emphasis is placed on individual members."},
{"t":"Sentence Correction","q":"He has been absent _____ Monday.","a":"for","b":"from","c":"during","d":"since","ans":"D","e":"*Since* is used with a specific point in time, while *for* is used with a duration."},
{"t":"Modifiers & Comparisons","q":"The more carefully you read, _____ you understand.","a":"best","b":"the best","c":"better","d":"the better","ans":"D","e":"The comparative correlative structure is *the more..., the better...*. This pattern is frequently examined in FPSC grammar sections. **FPSC Medical Officer English Grammar MCQs (61–90)** *High-yield grammar patterns repeatedly seen in FPSC, CSS, PMS, FIA, ASF, Inspector, Lecturer, and Medical Officer screening examinations.*"},
{"t":"Sentence Correction","q":"None of the information _____ useful.","a":"are","b":"have been","c":"is","d":"were","ans":"C","e":"*Information* is an uncountable noun and takes a singular verb. FPSC frequently tests agreement with uncountable nouns such as information, advice, furniture, and luggage."},
{"t":"Relative Pronouns","q":"He is not only intelligent _____ hardworking.","a":"but also","b":"as well","c":"moreover","d":"and also","ans":"A","e":"The correct correlative conjunction pair is *not only...but also*. Both parts must be used together for grammatical balance."},
{"t":"Tenses","q":"The train _____ before we reached the station.","a":"has left","b":"leaves","c":"leaving","d":"had left","ans":"D","e":"Since one past action occurred before another past action, the earlier action takes the past perfect tense (*had left*)."},
{"t":"Prepositions","q":"He objected _____ the proposal.","a":"with","b":"against","c":"to","d":"on","ans":"C","e":"The correct expression is *object to something*. Preposition questions of this type appear frequently in FPSC papers."},
{"t":"Sentence Correction","q":"Neither of these answers _____ correct.","a":"were","b":"are","c":"have been","d":"is","ans":"D","e":"*Neither* is grammatically singular and therefore requires a singular verb."},
{"t":"Prepositions","q":"The patient died _____ cancer.","a":"of","b":"with","c":"by","d":"from","ans":"A","e":"The standard expression is *die of a disease*. FPSC often tests commonly confused prepositions."},
{"t":"Tenses","q":"I wish I _____ there yesterday.","a":"had been","b":"have been","c":"were","d":"was","ans":"A","e":"When expressing regret about the past, *wish* is followed by the past perfect tense."},
{"t":"Sentence Correction","q":"Every student and every teacher _____ required to attend.","a":"is","b":"have been","c":"were","d":"are","ans":"A","e":"When singular nouns are joined by *every...and every*, the verb remains singular."},
{"t":"Prepositions","q":"He is addicted _____ smoking.","a":"to","b":"with","c":"at","d":"in","ans":"A","e":"The correct collocation is *addicted to*. Similar prepositional combinations are highly testable."},
{"t":"Sentence Correction","q":"Rarely _____ such an opportunity arise.","a":"do","b":"does","c":"has","d":"did","ans":"A","e":"With *rarely* at the beginning, inversion occurs. Since the subject is singular opportunity? Wait: actual structure is \"Rarely does such an opportunity arise.\" Let's use singular. Correct answer should be A. **Answer: A** **Explanation:** Beginning a sentence with *rarely* requires inversion. Because *opportunity* is singular, *does* is required."},
{"t":"Sentence Correction","q":"The jury _____ unanimous in its verdict.","a":"are","b":"is","c":"were","d":"have","ans":"B","e":"When a collective noun acts as one unit, it takes a singular verb. FPSC often tests collective nouns."},
{"t":"Sentence Correction","q":"She succeeded _____ passing the examination.","a":"at","b":"in","c":"for","d":"on","ans":"B","e":"The correct structure is *succeed in doing something*."},
{"t":"Conditionals","q":"Had it not rained, we _____ the match.","a":"would play","b":"would have played","c":"played","d":"had played","ans":"B","e":"This is a third conditional sentence referring to an unreal past situation."},
{"t":"Sentence Correction","q":"The amount of money _____ insufficient.","a":"have been","b":"is","c":"were","d":"are","ans":"B","e":"*Amount* is singular, so the verb must also be singular regardless of the noun following it."},
{"t":"Sentence Correction","q":"He insisted _____ seeing the manager personally.","a":"in","b":"on","c":"for","d":"at","ans":"B","e":"The correct expression is *insist on doing something*."},
{"t":"Sentence Correction","q":"Scarcely had he spoken _____ the audience started clapping.","a":"when","b":"than","c":"that","d":"then","ans":"A","e":"The accepted construction is *Scarcely...when*."},
{"t":"Sentence Correction","q":"Mathematics _____ my favorite subject.","a":"were","b":"are","c":"have been","d":"is","ans":"D","e":"Names of academic subjects ending in *-s* are usually singular in meaning."},
{"t":"Sentence Correction","q":"She is afraid _____ dogs.","a":"with","b":"from","c":"by","d":"of","ans":"D","e":"The standard expression is *afraid of*."},
{"t":"Sentence Correction","q":"If I _____ your position, I would accept the offer.","a":"am","b":"were","c":"had been","d":"was","ans":"B","e":"In hypothetical present situations, *were* is preferred for all subjects."},
{"t":"Subject-Verb Agreement","q":"Either the principal or the teachers _____ responsible.","a":"was","b":"are","c":"is","d":"has been","ans":"B","e":"With *either...or*, the verb agrees with the nearest subject. Here, *teachers* is plural."},
{"t":"Prepositions","q":"He is capable of _____ difficult situations.","a":"handling","b":"handle","c":"to handle","d":"handled","ans":"A","e":"A preposition (*of*) must be followed by a gerund, not an infinitive."},
{"t":"Sentence Correction","q":"Not until the teacher arrived _____ the class begin.","a":"does","b":"had","c":"has","d":"did","ans":"D","e":"Negative introductory expressions require inversion. *Did* correctly forms the inverted structure."},
{"t":"Sentence Correction","q":"One-third of the work _____ completed.","a":"is","b":"were","c":"are","d":"have been","ans":"A","e":"The noun *work* is uncountable, so the verb remains singular."},
{"t":"Prepositions","q":"He congratulated me _____ my success.","a":"over","b":"for","c":"on","d":"at","ans":"C","e":"The correct collocation is *congratulate someone on something*."},
{"t":"Conditionals","q":"She would have attended the meeting if she _____ informed.","a":"were","b":"has been","c":"had been","d":"was","ans":"C","e":"This is a third conditional structure requiring *had been* in the if-clause."},
{"t":"Sentence Correction","q":"The police _____ investigating the matter.","a":"was","b":"are","c":"has been","d":"is","ans":"B","e":"*Police* is treated as a plural noun in standard English grammar."},
{"t":"Sentence Correction","q":"He abstained _____ commenting on the issue.","a":"in","b":"by","c":"at","d":"from","ans":"D","e":"The correct expression is *abstain from doing something*."},
{"t":"Tenses","q":"Never before _____ such a remarkable discovery been made.","a":"has","b":"was","c":"have","d":"had","ans":"A","e":"Negative adverbials placed first require inversion. Present perfect is appropriate here."},
{"t":"Sentence Correction","q":"The secretary as well as the members _____ present.","a":"have been","b":"was","c":"are","d":"were","ans":"B","e":"Phrases like *as well as* do not affect agreement. The verb agrees with *secretary*."},
{"t":"Modifiers & Comparisons","q":"The sooner we leave, _____ we will arrive.","a":"the earlier","b":"earlier","c":"the earliest","d":"earliest","ans":"A","e":"This follows the comparative correlative pattern: *The sooner..., the earlier...*, a favorite FPSC grammar structure. **FPSC Medical Officer English Grammar MCQs (91–120)** *Focused on the highest-yield grammar rules repeatedly tested across FPSC, CSS, PMS, FIA, ASF, AD IB, Lecturer, and Medical Officer examinations. These questions emphasize error patterns that examiners repeatedly recycle.*"},
{"t":"Sentence Correction","q":"Each of the doctors _____ required to submit a report.","a":"have been","b":"is","c":"are","d":"were","ans":"B","e":"*Each* is always singular and takes a singular verb. FPSC frequently tests this rule using plural nouns after *each of*."},
{"t":"Sentence Correction","q":"He has been working in this hospital _____ ten years.","a":"since","b":"by","c":"from","d":"for","ans":"D","e":"*For* is used with a period of time (ten years), whereas *since* is used with a specific point in time."},
{"t":"Subject-Verb Agreement","q":"Neither Ali nor his brothers _____ interested in politics.","a":"is","b":"has been","c":"are","d":"was","ans":"C","e":"In *neither...nor* constructions, the verb agrees with the subject nearest to it. Here, *brothers* is plural."},
{"t":"Subject-Verb Agreement","q":"The chairman, along with his staff, _____ attending the ceremony.","a":"have been","b":"were","c":"are","d":"is","ans":"D","e":"Expressions such as *along with*, *together with*, and *as well as* do not affect subject-verb agreement. The verb agrees with *chairman*."},
{"t":"Sentence Correction","q":"Hardly had the speech ended _____ the audience began applauding.","a":"then","b":"that","c":"than","d":"when","ans":"D","e":"The fixed structure is *Hardly...when*. This is among the most repeated grammar patterns in competitive examinations."},
{"t":"Subject-Verb Agreement","q":"One of my friends _____ selected for the scholarship.","a":"was","b":"are","c":"were","d":"have been","ans":"A","e":"The true subject is *one*, which is singular. Therefore, a singular verb is required."},
{"t":"Sentence Correction","q":"He is superior _____ his colleagues in administrative skills.","a":"from","b":"to","c":"over","d":"than","ans":"B","e":"Adjectives such as *superior, inferior, senior,* and *junior* are followed by *to*, not *than*."},
{"t":"Conditionals","q":"If he had informed me earlier, I _____ him.","a":"would have helped","b":"helped","c":"would help","d":"help","ans":"A","e":"This is a third conditional sentence. The result clause must contain *would have + past participle*."},
{"t":"Sentence Correction","q":"The furniture in these rooms _____ quite expensive.","a":"have been","b":"were","c":"is","d":"are","ans":"C","e":"*Furniture* is an uncountable noun and always takes a singular verb."},
{"t":"Sentence Correction","q":"She insisted _____ accompanying us.","a":"with","b":"at","c":"on","d":"in","ans":"C","e":"The correct structure is *insist on doing something*."},
{"t":"Sentence Correction","q":"No sooner had we entered the building _____ the fire alarm rang.","a":"than","b":"when","c":"then","d":"that","ans":"A","e":"The standard grammatical construction is *No sooner...than*."},
{"t":"Pronouns","q":"Everybody _____ responsible for maintaining discipline.","a":"are","b":"were","c":"is","d":"have been","ans":"C","e":"Indefinite pronouns such as *everybody, everyone, somebody,* and *nobody* are singular."},
{"t":"Prepositions","q":"He was accused _____ theft.","a":"of","b":"from","c":"with","d":"for","ans":"A","e":"The correct collocation is *accused of*. Prepositional combinations are commonly tested."},
{"t":"Tenses","q":"I wish I _____ the opportunity last year.","a":"accept","b":"had accepted","c":"accepted","d":"have accepted","ans":"B","e":"Regret about a past action requires the past perfect tense after *wish*."},
{"t":"Sentence Correction","q":"A number of candidates _____ absent from the examination.","a":"is","b":"was","c":"are","d":"has been","ans":"C","e":"*A number of* takes a plural verb because it refers to several individuals."},
{"t":"Sentence Correction","q":"The number of candidates _____ increasing every year.","a":"were","b":"have been","c":"are","d":"is","ans":"D","e":"*The number of* refers to a single quantity and therefore takes a singular verb."},
{"t":"Sentence Correction","q":"He succeeded _____ obtaining the required documents.","a":"in","b":"on","c":"at","d":"by","ans":"A","e":"The correct phrase is *succeed in doing something*."},
{"t":"Modifiers & Comparisons","q":"Seldom _____ such honesty in public life.","a":"we find","b":"we found","c":"do we find","d":"found we","ans":"C","e":"Introductory negative adverbs require inversion. Therefore, *do we find* is correct."},
{"t":"Subject-Verb Agreement","q":"Neither the principal nor the teachers _____ available.","a":"are","b":"is","c":"has been","d":"was","ans":"A","e":"The verb agrees with the nearest subject (*teachers*), which is plural."},
{"t":"Sentence Correction","q":"He prevented the child _____ crossing the road alone.","a":"in","b":"at","c":"from","d":"by","ans":"C","e":"The standard construction is *prevent someone from doing something*."},
{"t":"Sentence Correction","q":"The committee _____ reached its final decision.","a":"were","b":"has","c":"have","d":"are","ans":"B","e":"When a committee acts as one unit, it takes a singular verb in standard exam grammar."},
{"t":"Prepositions","q":"She is looking forward to _____ her training.","a":"completing","b":"completed","c":"to complete","d":"complete","ans":"A","e":"*To* in this expression is a preposition, so it must be followed by a gerund."},
{"t":"Modifiers & Comparisons","q":"Had I known the facts, I _____ differently.","a":"acted","b":"would have acted","c":"act","d":"would act","ans":"B","e":"An unreal past condition requires *would have + past participle* in the result clause."},
{"t":"Sentence Correction","q":"The police _____ searching for the suspect.","a":"are","b":"was","c":"is","d":"has been","ans":"A","e":"*Police* is treated as a plural noun and therefore takes a plural verb."},
{"t":"Sentence Correction","q":"He is capable _____ managing a large hospital.","a":"to","b":"for","c":"with","d":"of","ans":"D","e":"The correct expression is *capable of doing something*."},
{"t":"Sentence Correction","q":"Rarely _____ a candidate answer all questions correctly.","a":"do","b":"has","c":"does","d":"did","ans":"C","e":"After *rarely*, inversion occurs. Since *candidate* is singular, *does* is correct."},
{"t":"Subject-Verb Agreement","q":"Either the doctors or the administrator _____ responsible.","a":"were","b":"have been","c":"is","d":"are","ans":"C","e":"In *either...or* structures, the verb agrees with the nearest subject. *Administrator* is singular."},
{"t":"Sentence Correction","q":"He abstained _____ making any comments.","a":"in","b":"with","c":"from","d":"by","ans":"C","e":"The accepted structure is *abstain from doing something*."},
{"t":"Subject-Verb Agreement","q":"Not only the nurses but also the surgeon _____ informed.","a":"have been","b":"was","c":"were","d":"are","ans":"B","e":"With *not only...but also*, the verb agrees with the nearest subject. *Surgeon* is singular."},
{"t":"Conditionals","q":"The more experience you gain, _____ your confidence becomes.","a":"the highest","b":"higher","c":"the higher","d":"highest","ans":"C","e":"This follows the comparative correlative pattern: *The more..., the higher...*. FPSC repeatedly tests this structure. **FPSC Medical Officer English Grammar MCQs (121–150)** *Built around the grammar patterns most frequently recycled in FPSC, CSS, PMS, FIA, ASF, AD IB, Lecturer, and Medical Officer examinations: subject-verb agreement, conditionals, prepositions, inversion, gerunds, infinitives, and sentence correction.*"},
{"t":"Pronouns","q":"Everyone in the class _____ submitted the assignment.","a":"are","b":"have","c":"has","d":"were","ans":"C","e":"*Everyone* is an indefinite pronoun and is grammatically singular. Therefore, it requires the singular verb *has*."},
{"t":"Prepositions","q":"He is interested _____ learning foreign languages.","a":"in","b":"for","c":"on","d":"at","ans":"A","e":"The correct collocation is *interested in*. Preposition-based questions of this type appear regularly in FPSC papers."},
{"t":"Tenses","q":"If she _____ earlier, she would catch the train.","a":"leaves","b":"had left","c":"would leave","d":"left","ans":"D","e":"This is a second conditional sentence expressing a present unreal situation. The if-clause takes the past simple tense."},
{"t":"Subject-Verb Agreement","q":"The quality of these medicines _____ excellent.","a":"have been","b":"are","c":"is","d":"were","ans":"C","e":"The true subject is *quality*, which is singular. The plural noun *medicines* does not affect the verb."},
{"t":"Gerunds & Infinitives","q":"He is accustomed _____ getting up early.","a":"at","b":"to","c":"for","d":"with","ans":"B","e":"*Accustomed to* is followed by a noun or gerund. FPSC frequently tests this structure."},
{"t":"Sentence Correction","q":"Not until the report was completed _____ the committee meet.","a":"has","b":"had","c":"did","d":"does","ans":"C","e":"Negative introductory expressions require inversion. Therefore, *did the committee meet* is the correct structure."},
{"t":"Sentence Correction","q":"The cattle _____ grazing in the field.","a":"are","b":"is","c":"was","d":"has been","ans":"A","e":"*Cattle* is treated as a plural noun and takes a plural verb."},
{"t":"Sentence Correction","q":"He apologized _____ being late.","a":"for","b":"with","c":"at","d":"from","ans":"A","e":"The correct expression is *apologize for something* or *apologize for doing something*."},
{"t":"Conditionals","q":"Had they prepared properly, they _____ the project successfully.","a":"complete","b":"would complete","c":"completed","d":"would have completed","ans":"D","e":"This is a third conditional sentence describing an unreal past outcome."},
{"t":"Sentence Correction","q":"Neither of the proposals _____ acceptable.","a":"is","b":"were","c":"are","d":"have been","ans":"A","e":"*Neither* is singular and therefore takes a singular verb."},
{"t":"Sentence Correction","q":"She insisted that the patient _____ immediately.","a":"is admitted","b":"was admitted","c":"admitted","d":"be admitted","ans":"D","e":"After verbs like *insist, recommend,* and *suggest*, the subjunctive form (*be admitted*) is preferred."},
{"t":"Prepositions","q":"He has confidence _____ his abilities.","a":"by","b":"in","c":"on","d":"at","ans":"B","e":"The standard collocation is *confidence in*."},
{"t":"Sentence Correction","q":"The audience _____ requested to remain seated.","a":"were","b":"are","c":"was","d":"have been","ans":"C","e":"In FPSC-style grammar, *audience* is usually treated as a singular collective noun when acting as one unit."},
{"t":"Sentence Correction","q":"Scarcely had the lecture begun _____ the electricity failed.","a":"when","b":"that","c":"then","d":"than","ans":"A","e":"The accepted structure is *Scarcely...when*. This is a favorite competitive-exam grammar pattern."},
{"t":"Relative Pronouns","q":"One of the candidates who _____ shortlisted has withdrawn.","a":"was","b":"is","c":"were","d":"has","ans":"C","e":"The relative clause refers to *candidates* (plural), so the plural verb *were* is correct."},
{"t":"Sentence Correction","q":"She is capable _____ handling emergency situations.","a":"to","b":"with","c":"for","d":"of","ans":"D","e":"The correct construction is *capable of doing something*."},
{"t":"Sentence Correction","q":"The data _____ carefully analyzed before publication.","a":"were","b":"is","c":"has been","d":"was","ans":"A","e":"In formal grammar, *data* is traditionally treated as plural. This distinction is occasionally tested in competitive exams."},
{"t":"Sentence Correction","q":"Rarely _____ such commitment among public servants.","a":"observed we","b":"we observed","c":"we observe","d":"do we observe","ans":"D","e":"After *rarely*, inversion is required. Therefore, *do we observe* is grammatically correct."},
{"t":"Sentence Correction","q":"He refrained _____ making any statement.","a":"in","b":"from","c":"by","d":"with","ans":"B","e":"The correct phrase is *refrain from doing something*."},
{"t":"Subject-Verb Agreement","q":"Either the manager or the employees _____ responsible for the loss.","a":"was","b":"is","c":"are","d":"has been","ans":"C","e":"In *either...or* constructions, the verb agrees with the nearest subject. Here, *employees* is plural."},
{"t":"Sentence Correction","q":"The number of patients _____ increasing steadily.","a":"were","b":"is","c":"have been","d":"are","ans":"B","e":"*The number of* always takes a singular verb because it refers to one numerical quantity."},
{"t":"Gerunds & Infinitives","q":"He succeeded because he was determined _____ succeed.","a":"with","b":"for","c":"at","d":"to","ans":"D","e":"The adjective *determined* is followed by the infinitive form: *determined to succeed*."},
{"t":"Tenses","q":"I wish I _____ more time to prepare for the interview.","a":"having","b":"had","c":"had had","d":"have","ans":"B","e":"A present unreal wish requires the past simple tense after *wish*."},
{"t":"Sentence Correction","q":"Much of the work _____ already completed.","a":"are","b":"has been","c":"have been","d":"were","ans":"B","e":"*Work* is an uncountable noun and takes a singular verb."},
{"t":"Sentence Correction","q":"He is responsible _____ maintaining hospital records.","a":"for","b":"with","c":"by","d":"to","ans":"A","e":"The correct expression is *responsible for*."},
{"t":"Sentence Correction","q":"No sooner had the results been announced _____ the celebrations began.","a":"that","b":"than","c":"then","d":"when","ans":"B","e":"The fixed construction is *No sooner...than*. It appears frequently in grammar MCQs."},
{"t":"Sentence Correction","q":"The jury _____ unable to reach a unanimous decision.","a":"was","b":"has","c":"were","d":"is","ans":"C","e":"When emphasis is on individual members acting differently, *jury* may take a plural verb."},
{"t":"Gerunds & Infinitives","q":"She devoted herself _____ helping underprivileged children.","a":"to","b":"with","c":"at","d":"for","ans":"A","e":"*Devote oneself to* is followed by a noun or gerund."},
{"t":"Modifiers & Comparisons","q":"Seldom _____ a mistake of this magnitude.","a":"encountered we","b":"we encountered","c":"we encounter","d":"do we encounter","ans":"D","e":"Introductory negative adverbs require inversion, making *do we encounter* correct."},
{"t":"Modifiers & Comparisons","q":"The more thoroughly you investigate, _____ the conclusions become.","a":"more accurate","b":"most accurate","c":"accurate","d":"the more accurate","ans":"D","e":"This follows the comparative correlative structure: *The more..., the more...*, a highly tested grammar pattern in FPSC examinations. **English Grammar Usage MCQs (151–180) — Revised High-Yield Set**"},
{"t":"Relative Pronouns","q":"One of the books that _____ recommended by the examiner is difficult to find.","a":"has","b":"were","c":"is","d":"was","ans":"B","e":"The relative clause *that were recommended by the examiner* refers to *books*, not *one*. Since *books* is plural, the verb inside the relative clause must also be plural."},
{"t":"Sentence Correction","q":"He has been suffering from fever _____ Monday.","a":"for","b":"during","c":"from","d":"since","ans":"D","e":"*Since* is used with a specific starting point in time (Monday, 2019, January, etc.). *For* is used with a duration such as two days, three weeks, or ten years."},
{"t":"Subject-Verb Agreement","q":"The officer as well as his assistants _____ invited to the conference.","a":"are","b":"were","c":"have been","d":"was","ans":"D","e":"Expressions such as *as well as*, *along with*, and *together with* do not change the subject. The verb agrees with *officer*, which is singular."},
{"t":"Conditionals","q":"Had the patient arrived earlier, the doctor _____ him personally.","a":"had examined","b":"would have examined","c":"examined","d":"would examine","ans":"B","e":"This is a third conditional sentence expressing an unreal past event. The correct structure is *Had + subject + past participle*, followed by *would have + past participle*."},
{"t":"Sentence Correction","q":"The sentence contains an error: ****\"****Neither of the reports were submitted on time.****\"","a":"were","b":"Neither","c":"time","d":"reports","ans":"A","e":"*Neither* is grammatically singular. Therefore, the correct verb should be *was*, not *were*, regardless of the plural noun that follows."},
{"t":"Prepositions","q":"He is looking forward to _____ the training workshop.","a":"attend","b":"attending","c":"be attending","d":"attended","ans":"B","e":"In the phrase *look forward to*, the word *to* is a preposition, not part of an infinitive. Therefore, it must be followed by a noun or a gerund (*-ing* form)."},
{"t":"Tenses","q":"If I _____ the authority, I would revise the policy.","a":"had had","b":"had","c":"having","d":"have","ans":"B","e":"This is a second conditional sentence expressing a hypothetical present situation. The if-clause takes the past simple tense, while the result clause uses *would + base verb*."},
{"t":"Subject-Verb Agreement","q":"The manager demanded that every employee _____ present at the meeting.","a":"is","b":"was","c":"be","d":"being","ans":"C","e":"After verbs such as *demand, insist, recommend,* and *suggest*, the subjunctive form is used. Therefore, *be* remains unchanged regardless of the subject."},
{"t":"Modifiers & Comparisons","q":"Which sentence is grammatically correct?","a":"He is senior than me.","b":"He is senior from me.","c":"He is senior to me.","d":"He is senior over me.","ans":"C","e":"Certain comparative adjectives such as *senior, junior, superior,* and *inferior* are followed by *to*, not *than*."},
{"t":"Sentence Correction","q":"The jury _____ divided in their opinions.","a":"has","b":"were","c":"was","d":"is","ans":"B","e":"When the members of a collective noun are acting individually or holding different views, a plural verb may be used. Here, the jury members are not in agreement."},
{"t":"Prepositions","q":"The report was discussed _____ detail.","a":"in","b":"with","c":"on","d":"by","ans":"A","e":"The fixed expression is *in detail*, meaning thoroughly or comprehensively. The other prepositions do not form a correct idiomatic phrase."},
{"t":"Relative Pronouns","q":"Not only did he complete the task, _____ he also improved the process.","a":"but","b":"and","c":"therefore","d":"however","ans":"A","e":"The correct correlative conjunction pair is *not only...but also*. Both parts work together to connect two related ideas."},
{"t":"Tenses","q":"By the time we reached the venue, the ceremony _____.","a":"beginning","b":"begins","c":"has begun","d":"had begun","ans":"D","e":"When one action occurred before another action in the past, the earlier action is expressed in the past perfect tense (*had begun*)."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The scenery were beautiful.","b":"The scenery was beautiful.","c":"The sceneries were beautiful.","d":"The sceneries was beautiful.","ans":"B","e":"*Scenery* is an uncountable noun and does not normally have a plural form. Therefore, it takes a singular verb."},
{"t":"Gerunds & Infinitives","q":"He would rather _____ at home than go out in bad weather.","a":"stayed","b":"stay","c":"staying","d":"to stay","ans":"B","e":"After *would rather*, the base form of the verb is used. No infinitive marker (*to*) or gerund is required."},
{"t":"Sentence Correction","q":"There _____ a pen and three notebooks on the table.","a":"are","b":"is","c":"have been","d":"were","ans":"B","e":"In *there is/there are* constructions, the verb usually agrees with the nearest noun. Since *a pen* comes first, *is* is correct."},
{"t":"Sentence Correction","q":"The principal ordered that the meeting _____ postponed.","a":"being","b":"was","c":"is","d":"be","ans":"D","e":"After verbs expressing orders, requests, or recommendations, English uses the subjunctive form. Hence, *be postponed* is correct."},
{"t":"Sentence Correction","q":"Which sentence is free from error?","a":"Each of the boys have completed the task.","b":"Each of the boys has completed the task.","c":"Each of the boys are completing the task.","d":"Each of the boys were completing the task.","ans":"B","e":"Although *boys* is plural, the true subject is *each*, which is singular and requires *has*."},
{"t":"Sentence Correction","q":"He is not accustomed _____ such long working hours.","a":"by","b":"for","c":"with","d":"to","ans":"D","e":"The correct expression is *accustomed to*. When followed by a verb, that verb takes the *-ing* form."},
{"t":"Sentence Correction","q":"I wish I _____ what was going to happen.","a":"had known","b":"know","c":"knowing","d":"knew","ans":"D","e":"This sentence expresses a present regret or unreal situation. After *wish*, the past simple is used for present unreal meanings."},
{"t":"Modifiers & Comparisons","q":"Which sentence is grammatically correct?","a":"She speaks fluently English.","b":"She fluent speaks English.","c":"She speaks English fluently.","d":"She speaks English fluent.","ans":"C","e":"Verbs are modified by adverbs, not adjectives. Therefore, *fluently* correctly modifies the verb *speaks*."},
{"t":"Sentence Correction","q":"The teacher, together with the students, _____ attending the seminar.","a":"were","b":"is","c":"are","d":"have been","ans":"B","e":"The phrase *together with the students* is additional information and does not affect agreement. The verb agrees with *teacher*."},
{"t":"Tenses","q":"If the weather improves, we _____ the match tomorrow.","a":"play","b":"played","c":"will play","d":"would play","ans":"C","e":"In a first conditional sentence, the if-clause takes the present tense, while the main clause takes the future tense."},
{"t":"Prepositions","q":"Which word completes the sentence correctly? ****\"****He is capable _____ leading a large team.****\"","a":"to","b":"with","c":"of","d":"for","ans":"C","e":"The standard structure is *capable of + noun/gerund*. Other prepositions are grammatically incorrect in this context."},
{"t":"Sentence Correction","q":"The news _____ unexpected and disturbing.","a":"have been","b":"was","c":"are","d":"were","ans":"B","e":"Although *news* ends in *-s*, it is treated as a singular noun and takes a singular verb."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The patient as well as the nurses were informed.","b":"The patient as well as the nurses have been informed.","c":"The patient as well as the nurses was informed.","d":"The patient as well as the nurses are informed.","ans":"C","e":"When *as well as* connects two nouns, the verb agrees with the first noun. Here, *patient* is singular."},
{"t":"Sentence Correction","q":"Hardly had the train left the station _____ it began to rain.","a":"then","b":"when","c":"than","d":"that","ans":"B","e":"The standard pairing is *Hardly...when*. Similar constructions include *No sooner...than* and *Scarcely...when*."},
{"t":"Modifiers & Comparisons","q":"The more carefully the prescription is followed, _____ the recovery.","a":"faster","b":"the faster","c":"fastest","d":"the fastest","ans":"B","e":"Comparative correlative structures follow the pattern *the more..., the faster...*. Both parts require *the* before the comparative adjective."},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"One of my friends is a surgeon.","b":"One of my friend is a surgeon.","c":"One of my friends are surgeons.","d":"One of my friends are a surgeon.","ans":"A","e":"After *one of*, the noun should be plural (*friends*), but the verb remains singular because the subject is *one*."},
{"t":"Tenses","q":"The committee has appointed a new secretary, _____ will assume office next month.","a":"whom","b":"whose","c":"who","d":"which","ans":"C","e":"The relative pronoun refers to *secretary*, a person. Therefore, *who* is the correct choice. *Whom* would be used as an object, not as the subject of the clause. **English Grammar Usage MCQs (181–210)** *This batch focuses on grammar areas that are historically among the most tested in competitive examinations: modifiers, pronouns, parallelism, articles, tense sequence, conditionals, inversion, agreement, and sentence correction. The aim is to avoid repetition and target patterns that examiners frequently recycle in new forms.*"},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Each candidate must bring his or her admit card.","b":"Each candidate must bring their admit card.","c":"Each candidate must brought his admit card.","d":"Each candidate must brings his admit card.","ans":"A","e":"In formal grammar, *each candidate* is singular and traditionally takes *his or her*. The other options contain agreement or verb-form errors."},
{"t":"Sentence Correction","q":"The patient had scarcely recovered _____ he resumed work.","a":"then","b":"that","c":"when","d":"than","ans":"C","e":"The standard construction is *Scarcely...when*. Similar fixed pairs include *Hardly...when* and *No sooner...than*."},
{"t":"Pronouns","q":"Which sentence contains no error?","a":"He is one of those doctor who work tirelessly.","b":"He is one of those doctors who works tirelessly.","c":"He is one of those doctors who working tirelessly.","d":"He is one of those doctors who work tirelessly.","ans":"D","e":"The relative pronoun *who* refers to *doctors*, which is plural. Therefore, the verb must also be plural (*work*)."},
{"t":"Tenses","q":"By next June, she _____ in this institution for ten years.","a":"will work","b":"will have worked","c":"has worked","d":"had worked","ans":"B","e":"The future perfect tense is used for an action that will be completed by a specified future time."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The rich are becoming richer.","b":"The rich becomes richer.","c":"The rich has become richer.","d":"The rich is becoming richer.","ans":"A","e":"*The rich* refers to a group of people and therefore takes a plural verb."},
{"t":"Prepositions","q":"He objected _____ being transferred to another department.","a":"for","b":"with","c":"to","d":"against","ans":"C","e":"The verb *object* is followed by the preposition *to*. When a verb follows, it takes the gerund form."},
{"t":"Conditionals","q":"If he _____ more carefully, he would not make so many mistakes.","a":"reads","b":"read","c":"had read","d":"has read","ans":"B","e":"This is a second conditional sentence expressing a hypothetical present situation."},
{"t":"Prepositions","q":"Which sentence is free from error?","a":"The reason with his absence is unknown.","b":"The reason of his absence is unknown.","c":"The reason for his absence is unknown.","d":"The reason to his absence is unknown.","ans":"C","e":"The correct idiomatic expression is *the reason for*. This collocation is frequently tested."},
{"t":"Subject-Verb Agreement","q":"No less than twenty students _____ selected.","a":"was","b":"were","c":"has been","d":"is","ans":"B","e":"The actual subject is *twenty students*, which is plural. Therefore, a plural verb is required."},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Neither he nor I were responsible.","b":"Neither he nor I are responsible.","c":"Neither he nor I is responsible.","d":"Neither he nor I am responsible.","ans":"D","e":"In *neither...nor* constructions, the verb agrees with the nearest subject. Since *I* takes *am*, option A is correct."},
{"t":"Pronouns","q":"The proposal was rejected, _____ surprised everyone.","a":"which","b":"who","c":"whom","d":"that","ans":"A","e":"*Which* can refer to an entire preceding clause, making it the correct relative pronoun here."},
{"t":"Tenses","q":"He behaves as though he _____ everything.","a":"knows","b":"knowing","c":"knew","d":"had known","ans":"C","e":"After *as though* or *as if* expressing an unreal situation, the past tense is commonly used."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"She has lesser books than her sister.","b":"She has less books than her sister.","c":"She has fewer books than her sister.","d":"She has few books than her sister.","ans":"C","e":"*Fewer* is used with countable nouns such as books, while *less* is used with uncountable nouns."},
{"t":"Sentence Correction","q":"The chairman and managing director _____ arriving today.","a":"have","b":"are","c":"were","d":"is","ans":"D","e":"When two titles refer to the same person, a singular verb is used."},
{"t":"Gerunds & Infinitives","q":"Which sentence is grammatically correct?","a":"She prefers reading to writing.","b":"She prefers read to write.","c":"She prefers reading over to writing.","d":"She prefers reading than writing.","ans":"A","e":"The standard structure is *prefer A to B*, whether nouns, pronouns, or gerunds are used."},
{"t":"Subject-Verb Agreement","q":"Hardly ever _____ such honesty in public life.","a":"do we encounter","b":"we encountered","c":"we encounter","d":"encountered we","ans":"A","e":"Negative or restrictive adverbs at the beginning of a sentence require subject-auxiliary inversion."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"He is one of the best surgeon's in the city.","b":"He is one of the best surgeons in the city.","c":"He is one of the best surgery in the city.","d":"He is one of the best surgeon in the city.","ans":"B","e":"After *one of the*, a plural noun must be used because the person belongs to a larger group."},
{"t":"Sentence Correction","q":"I would sooner resign than _____ unfair treatment.","a":"tolerating","b":"tolerated","c":"tolerate","d":"to tolerate","ans":"C","e":"After *would sooner...than*, the base form of the verb is used."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"The equipment was modern.","b":"The furniture was expensive.","c":"The information was useful.","d":"The luggage were heavy.","ans":"D","e":"*Luggage* is an uncountable noun and should take a singular verb (*was*), not *were*."},
{"t":"Sentence Correction","q":"Not until the investigation ended _____ the facts revealed.","a":"have been","b":"were","c":"was","d":"had been","ans":"B","e":"After *Not until* at the beginning, inversion occurs. Since *facts* is plural, *were* is correct."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Every member and every officer have been present.","b":"Every member and every officer were present.","c":"Every member and every officer are present.","d":"Every member and every officer was present.","ans":"D","e":"When singular nouns are preceded by *every*, the verb remains singular even if joined by *and*."},
{"t":"Sentence Correction","q":"He was prevented _____ attending the conference.","a":"by","b":"in","c":"from","d":"with","ans":"C","e":"The standard construction is *prevent someone from doing something*."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The United States were a large country.","b":"The United States is a large country.","c":"The United States have been a large country.","d":"The United States are a large country.","ans":"B","e":"Although plural in form, *The United States* is treated as a singular political entity."},
{"t":"Conditionals","q":"Had I been informed, I _____ the meeting.","a":"would have attended","b":"attended","c":"would attend","d":"attend","ans":"A","e":"This is a third conditional sentence referring to an unreal past event."},
{"t":"Sentence Correction","q":"Which sentence is free from error?","a":"One of my friend has qualified.","b":"One of my friends qualified have.","c":"One of my friends have qualified.","d":"One of my friends has qualified.","ans":"D","e":"After *one of*, the noun is plural but the verb agrees with *one*, making it singular."},
{"t":"Modifiers & Comparisons","q":"The more difficult the task, _____ the satisfaction after completion.","a":"the greatest","b":"greater","c":"greatest","d":"the greater","ans":"D","e":"Comparative correlative structures require *the* before both comparative forms."},
{"t":"Tenses","q":"Which sentence is grammatically correct?","a":"It is high time we had leave.","b":"It is high time we leave.","c":"It is high time we left.","d":"It is high time we leaving.","ans":"C","e":"After *It is high time*, English uses the past tense to express that something should already have happened."},
{"t":"Gerunds & Infinitives","q":"The suspect denied _____ the document.","a":"to sign","b":"sign","c":"signed","d":"signing","ans":"D","e":"The verb *deny* is followed by a gerund (*-ing* form), not an infinitive."},
{"t":"Subject-Verb Agreement","q":"Which sentence is correct?","a":"Nobody except the nurses were aware of the change.","b":"Nobody except the nurses are aware of the change.","c":"Nobody except the nurses was aware of the change.","d":"Nobody except the nurses have been aware of the change.","ans":"C","e":"The subject is *nobody*, which is singular. The phrase *except the nurses* does not affect subject-verb agreement."},
{"t":"Tenses","q":"Were he to accept the offer, he _____ a significant promotion.","a":"receives","b":"had received","c":"would receive","d":"received","ans":"C","e":"*Were he to...* is an inverted conditional structure equivalent to *If he were to...*. The result clause takes *would + base verb*. **English Grammar Usage MCQs (211–240)** *Advanced high-yield grammar focusing on structures that repeatedly appear in competitive examinations: modifiers, agreement traps, subjunctive mood, inversion, parallelism, pronouns, articles, and tense consistency.*"},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Each of the participants are receiving a certificate.","b":"Each of the participants were receiving a certificate.","c":"Each of the participants have received a certificate.","d":"Each of the participants has received a certificate.","ans":"D","e":"The true subject is *each*, which is singular. The plural noun *participants* often distracts candidates into choosing a plural verb."},
{"t":"Relative Pronouns","q":"He is interested not only in research _____ in teaching as well.","a":"and","b":"however","c":"also","d":"but","ans":"D","e":"The correct correlative conjunction is *not only...but also*. Here, *but* completes the structure before *also* appears later in the sentence."},
{"t":"Tenses","q":"By the end of this month, they _____ the project.","a":"will have completed","b":"complete","c":"completed","d":"will complete","ans":"A","e":"The future perfect tense is used for an action expected to be completed before a specified future time."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"Statistics is a useful field of study.","b":"Economics are difficult for some students.","c":"Physics is my favorite discipline.","d":"Mathematics is an interesting subject.","ans":"B","e":"Academic subjects ending in *-s* are generally treated as singular. Therefore, *Economics is* would be correct."},
{"t":"Gerunds & Infinitives","q":"The doctor advised the patient _____ smoking immediately.","a":"stopping","b":"to stop","c":"stopped","d":"stop","ans":"B","e":"The verb *advise* is commonly followed by an object plus infinitive: *advise someone to do something*."},
{"t":"Subject-Verb Agreement","q":"Rarely _____ such an impressive performance.","a":"do we witness","b":"we witness","c":"we witnessed","d":"witnessed we","ans":"A","e":"When *rarely* begins a sentence, inversion occurs. The auxiliary verb comes before the subject."},
{"t":"Relative Pronouns","q":"Which sentence is grammatically correct?","a":"One of the students who was selected have withdrawn.","b":"One of the students who were selected has withdrawn.","c":"One of the students who was selected has withdrawn.","d":"One of the student who were selected has withdrawn.","ans":"B","e":"The relative clause refers to *students*, making *were selected* correct. The main verb agrees with *one* and therefore takes *has*."},
{"t":"Gerunds & Infinitives","q":"He is accustomed _____ long working hours.","a":"by","b":"for","c":"to","d":"with","ans":"C","e":"*Accustomed to* is a fixed expression. When followed by a verb, that verb must take the gerund form."},
{"t":"Conditionals","q":"If she had followed the instructions carefully, she _____ the error.","a":"had avoided","b":"would avoid","c":"avoided","d":"would have avoided","ans":"D","e":"This is a third conditional sentence expressing an unreal past result."},
{"t":"Subject-Verb Agreement","q":"The quality of the products _____ improved significantly.","a":"are","b":"were","c":"has","d":"have","ans":"C","e":"The subject is *quality*, not *products*. Therefore, a singular verb is required."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"He is married to a doctor.","b":"He is married with a doctor.","c":"He is married from a doctor.","d":"He is married by a doctor.","ans":"A","e":"The standard English expression is *married to someone*."},
{"t":"Sentence Correction","q":"Hardly had the meeting begun _____ the electricity failed.","a":"that","b":"than","c":"then","d":"when","ans":"D","e":"The accepted construction is *Hardly...when*. This pattern is frequently tested in grammar examinations."},
{"t":"Sentence Correction","q":"Which sentence is free from error?","a":"Neither of the answers have been correct.","b":"Neither of the answers are correct.","c":"Neither of the answers were correct.","d":"Neither of the answers is correct.","ans":"D","e":"*Neither* is singular and therefore takes a singular verb despite the plural noun following it."},
{"t":"Subject-Verb Agreement","q":"The secretary, together with the staff members, _____ attending the conference.","a":"are","b":"is","c":"have been","d":"were","ans":"B","e":"Phrases such as *together with* do not affect subject-verb agreement. The verb agrees with *secretary*."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"I prefer tea than coffee.","b":"I prefer tea to coffee.","c":"I prefer tea over coffee.","d":"I prefer tea from coffee.","ans":"B","e":"The standard grammatical structure is *prefer A to B*. This is a commonly tested usage rule."},
{"t":"Sentence Correction","q":"Not until the report was published _____ the public aware of the issue.","a":"did become","b":"had become","c":"become","d":"became","ans":"A","e":"Beginning a sentence with *Not until* requires inversion. Therefore, *did become* is correct."},
{"t":"Sentence Correction","q":"The police _____ investigating the incident.","a":"has been","b":"are","c":"was","d":"is","ans":"B","e":"*Police* is treated as a plural noun in standard English and takes a plural verb."},
{"t":"Sentence Correction","q":"He congratulated her _____ securing first position.","a":"on","b":"for","c":"at","d":"over","ans":"A","e":"The correct expression is *congratulate someone on something*."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The news have been encouraging.","b":"The news were encouraging.","c":"The news are encouraging.","d":"The news is encouraging.","ans":"D","e":"Although it ends in *-s*, *news* is a singular noun and requires a singular verb."},
{"t":"Sentence Correction","q":"Had they acted promptly, the crisis _____.","a":"could have been avoided","b":"can be avoided","c":"could be avoided","d":"had avoided","ans":"A","e":"The sentence refers to an unreal past possibility, requiring *could have been avoided*."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Every boy and girl are required to register.","b":"Every boy and girl were required to register.","c":"Every boy and girl is required to register.","d":"Every boy and girl have to register.","ans":"C","e":"When singular nouns are joined by *and* and preceded by *every*, the verb remains singular."},
{"t":"Sentence Correction","q":"He refrained _____ commenting on the controversy.","a":"by","b":"in","c":"with","d":"from","ans":"D","e":"The correct phrase is *refrain from doing something*."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"One of my friend is a neurologist.","b":"One of my friends were a neurologist.","c":"One of my friends is a neurologist.","d":"One of my friends are a neurologist.","ans":"C","e":"After *one of*, the noun should be plural, but the verb agrees with *one* and remains singular."},
{"t":"Subject-Verb Agreement","q":"Seldom _____ such determination among young professionals.","a":"we see","b":"we saw","c":"do we see","d":"seen we","ans":"C","e":"Introductory negative adverbs require inversion of the auxiliary verb and subject."},
{"t":"Tenses","q":"The committee _____ its final recommendation yesterday.","a":"submitting","b":"submit","c":"submitted","d":"has submit","ans":"C","e":"The action was completed at a definite time in the past, so the simple past tense is required."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The furniture were imported from Italy.","b":"The furniture was imported from Italy.","c":"The furniture have been imported from Italy.","d":"The furnitures were imported from Italy.","ans":"B","e":"*Furniture* is an uncountable noun and takes a singular verb. It does not normally have a plural form."},
{"t":"Conditionals","q":"Were the proposal to be accepted, it _____ major reforms.","a":"had brought","b":"brings","c":"would bring","d":"brought","ans":"C","e":"This is an inverted conditional sentence equivalent to *If the proposal were accepted*."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"She insisted to pay the bill.","b":"She insisted for paying the bill.","c":"She insisted at paying the bill.","d":"She insisted on paying the bill.","ans":"D","e":"The correct structure is *insist on doing something*."},
{"t":"Modifiers & Comparisons","q":"The more thoroughly the evidence is reviewed, _____ the decision will be.","a":"soundest","b":"sound","c":"the soundest","d":"the sounder","ans":"D","e":"Comparative correlative structures follow the pattern *the more..., the + comparative*."},
{"t":"Tenses","q":"Which sentence is correct?","a":"It is high time we starting the meeting.","b":"It is high time we started the meeting.","c":"It is high time we have started the meeting.","d":"It is high time we start the meeting.","ans":"B","e":"After *It is high time*, English uses the past tense to indicate that the action is already overdue and should happen immediately. **Sources I used to identify high-yield grammar patterns** I did **not directly copy MCQs** from these sites. Instead, I used them to identify the grammar topics that repeatedly appear in competitive exams and then constructed fresh questions around those patterns: - TestPoint FPSC English past-paper compilations (grammar, vocabulary, sentence correction) ([TestPoint](https://testpoint.pk/paper-mcqs/4937/fpsc-all-past-papers-2024-english-mcqs?utm_source=chatgpt.com)) - Subject–Verb Agreement collections derived from past papers ([Scribd](https://www.scribd.com/document/872626475/ALL-Subject-Verb-Agreement-Past-Papers-MCQs?utm_source=chatgpt.com)) - English MCQ repositories used by FPSC/CSS/PMS candidates ([PakMcqs](https://pakmcqs.com/category/english-mcqs?utm_source=chatgpt.com)) - Competitive-exam grammar resources focusing on prepositions, agreement, inversion, and sentence correction ([TestPoint](https://testpoint.pk/subcategory-mcqs/preposition?utm_source=chatgpt.com)) The patterns that recur most often are: - Subject–Verb Agreement - Prepositions - Conditional Sentences - Gerunds vs Infinitives - Inversion - Collective Nouns - Parallel Structure - Pronoun Agreement - Articles - Error Detection ([TestPoint](https://testpoint.pk/paper-mcqs/4937/fpsc-all-past-papers-2024-english-mcqs?utm_source=chatgpt.com)) # **English Grammar Usage MCQs (241–270)**"},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Every one of the files have been checked.","b":"Every one of the files were checked.","c":"Every one of the files are checked.","d":"Every one of the files has been checked.","ans":"D","e":"The subject is *every one*, which is singular. Although *files* is plural, the verb must agree with *every one*, requiring *has been*."},
{"t":"Prepositions","q":"He is proficient _____ computer programming.","a":"with","b":"on","c":"at","d":"in","ans":"D","e":"The accepted expression is *proficient in*. Questions involving adjective-preposition combinations are common in competitive exams."},
{"t":"Conditionals","q":"If I had known about the vacancy, I _____ for it.","a":"had applied","b":"would apply","c":"would have applied","d":"applied","ans":"C","e":"This is a third conditional sentence referring to an unreal past situation. The result clause requires *would have + past participle*."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"The equipment is ready.","b":"The baggage are heavy.","c":"The machinery is old.","d":"The information is accurate.","ans":"B","e":"*Baggage* is an uncountable noun and takes a singular verb. The correct sentence would use *is heavy*."},
{"t":"Sentence Correction","q":"She insisted that the report _____ immediately.","a":"be submitted","b":"submitted","c":"was submitted","d":"is submitted","ans":"A","e":"After verbs expressing insistence, recommendation, or demand, English commonly uses the subjunctive form."},
{"t":"Sentence Correction","q":"Little _____ about the incident before the investigation.","a":"knew","b":"has known","c":"was known","d":"had known","ans":"C","e":"When *little* means \"almost nothing\" and appears at the beginning, the sentence often takes an inverted or emphatic structure."},
{"t":"Relative Pronouns","q":"Which sentence is correct?","a":"He is one of the employees who deserve promotion.","b":"He is one of employee who deserve promotion.","c":"He is one of the employees who deserves promotion.","d":"He is one of the employee who deserves promotion.","ans":"A","e":"The relative clause refers to *employees*, which is plural. Therefore, the verb inside the clause must also be plural."},
{"t":"Sentence Correction","q":"He is capable _____ far greater responsibility.","a":"of","b":"for","c":"with","d":"to","ans":"A","e":"The correct construction is *capable of*. This rule is tested repeatedly in grammar sections."},
{"t":"Tenses","q":"By the time the guests arrived, dinner _____.","a":"had been served","b":"was served","c":"has served","d":"serves","ans":"A","e":"The serving occurred before the guests arrived, so the earlier action takes the past perfect tense."},
{"t":"Subject-Verb Agreement","q":"Neither the manager nor the accountant _____ available yesterday.","a":"was","b":"are","c":"were","d":"have been","ans":"A","e":"In *neither...nor* constructions, the verb agrees with the nearest subject. Here, *accountant* is singular."},
{"t":"Prepositions","q":"Which sentence is grammatically correct?","a":"She is married by an architect.","b":"She is married to an architect.","c":"She is married with an architect.","d":"She is married from an architect.","ans":"B","e":"The accepted expression is *married to*. This is a frequently tested prepositional usage."},
{"t":"Subject-Verb Agreement","q":"Seldom _____ such dedication in public service.","a":"we witness","b":"we witnessed","c":"witnessed we","d":"do we witness","ans":"D","e":"Introductory restrictive adverbs such as *seldom* require inversion of subject and auxiliary verb."},
{"t":"Sentence Correction","q":"The majority of the work _____ already finished.","a":"have been","b":"is","c":"were","d":"are","ans":"B","e":"*Work* is an uncountable noun and takes a singular verb. The phrase *majority of* does not change this."},
{"t":"Prepositions","q":"He apologized _____ his behavior.","a":"for","b":"at","c":"with","d":"on","ans":"A","e":"The standard collocation is *apologize for something*."},
{"t":"Tenses","q":"Which sentence is correct?","a":"It is time we went.","b":"It is time we go.","c":"It is time we have gone.","d":"It is time we going.","ans":"A","e":"After *It is time*, English uses the past tense to indicate that an action is overdue."},
{"t":"Subject-Verb Agreement","q":"The chairman and founder of the organization _____ speaking.","a":"have been","b":"are","c":"is","d":"were","ans":"C","e":"Both titles refer to the same person, so the subject is singular and takes a singular verb."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"Few information was available.","b":"Little information was available.","c":"Many information was available.","d":"Several informations were available.","ans":"B","e":"*Information* is uncountable. Quantifiers such as *little* are used with uncountable nouns."},
{"t":"Sentence Correction","q":"Hardly had the results been declared _____ celebrations started.","a":"that","b":"than","c":"then","d":"when","ans":"D","e":"The fixed grammatical structure is *Hardly...when*."},
{"t":"Sentence Correction","q":"The doctor advised that the patient _____ complete bed rest.","a":"taking","b":"took","c":"takes","d":"take","ans":"D","e":"After *advise that*, the subjunctive form is commonly used, especially in formal English."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Neither of the plans are practical.","b":"Neither of the plans seem practically.","c":"Neither of the plans seems practical.","d":"Neither of the plans seem practical.","ans":"C","e":"*Neither* is singular and therefore requires *seems*, not *seem*."},
{"t":"Conditionals","q":"Were I offered the position, I _____ it immediately.","a":"accept","b":"had accepted","c":"accepted","d":"would accept","ans":"D","e":"*Were I...* is an inverted conditional structure equivalent to *If I were...*."},
{"t":"Sentence Correction","q":"He is responsible _____ ensuring compliance with regulations.","a":"with","b":"for","c":"to","d":"by","ans":"B","e":"The correct expression is *responsible for doing something*."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"The criterion are unclear.","b":"The criteria was unclear.","c":"The criteria is unclear.","d":"The criterion is unclear.","ans":"D","e":"*Criterion* is singular, while *criteria* is plural. This distinction is commonly tested."},
{"t":"Sentence Correction","q":"Not until the evidence was reviewed _____ the mistake discovered.","a":"had","b":"were","c":"has been","d":"was","ans":"D","e":"Beginning the sentence with *Not until* requires inversion. Since *mistake* is singular, *was* is correct."},
{"t":"Gerunds & Infinitives","q":"She objected _____ being transferred abroad.","a":"for","b":"with","c":"to","d":"against","ans":"C","e":"*Object to* is the correct construction. A following verb must appear in the gerund form."},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"One of the reasons is financial constraints.","b":"One of the reason is financial constraints.","c":"One of reasons is financial constraints.","d":"One of the reasons are financial constraints.","ans":"A","e":"After *one of the*, a plural noun is used, but the verb remains singular because the subject is *one*."},
{"t":"Modifiers & Comparisons","q":"The more complex the problem, _____ the solution required.","a":"most sophisticated","b":"the more sophisticated","c":"sophisticated","d":"more sophisticated","ans":"B","e":"Comparative correlative structures require *the + comparative* in both parts."},
{"t":"Sentence Correction","q":"No sooner had the chairman arrived _____ the session commenced.","a":"that","b":"then","c":"when","d":"than","ans":"D","e":"The standard structure is *No sooner...than*."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"Both A and B can be correct depending on meaning.","b":"The faculty is divided in its opinion.","c":"Neither A nor B is correct.","d":"The faculty are divided in their opinions.","ans":"A","e":"Collective nouns may take singular or plural verbs depending on whether the group is acting as a unit or as individuals."},
{"t":"Conditionals","q":"Had the warning been taken seriously, the accident _____.","a":"may be avoided","b":"avoided","c":"might have been avoided","d":"may avoid","ans":"C","e":"This is a third conditional sentence expressing a possible unreal result in the past. The correct structure is *might have been avoided*. **English Grammar Usage MCQs (271–300)** *This batch emphasizes high-yield grammar areas that have not been heavily repeated in previous sets: articles, modifiers, parallelism, pronouns, determiners, comparison structures, subjunctive mood, and sentence correction. Explanations are slightly richer to reinforce exam-relevant rules.*"},
{"t":"Articles","q":"Which sentence is grammatically correct?","a":"He is a European citizen.","b":"He is the European citizen.","c":"He is an European citizen.","d":"He is one European citizen.","ans":"A","e":"*European* begins with a consonant sound (/yoo/), so the correct article is *a*, not *an*. Remember: articles depend on sound, not spelling."},
{"t":"Tenses","q":"I would rather you _____ the matter confidential.","a":"keeping","b":"have kept","c":"keep","d":"kept","ans":"D","e":"After *would rather* when referring to another person's action, English uses the past tense. Example: *I'd rather you stayed home.*"},
{"t":"Modifiers & Comparisons","q":"Which sentence contains an error?","a":"He is taller than his brother.","b":"He is more taller than his brother.","c":"He is taller than I am.","d":"He is taller than me.","ans":"B","e":"Comparative adjectives like *taller* should not be preceded by *more*. This creates a double comparative, which is incorrect."},
{"t":"Pronouns","q":"The teacher asked whether _____ had completed the assignment.","a":"anyone","b":"everyone else","c":"someone","d":"no one","ans":"A","e":"In indirect questions and neutral contexts, *anyone* is generally preferred. This is a common pronoun-usage pattern."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Neither of the two proposal is practical.","b":"Neither of the two proposals is practical.","c":"Neither of the two proposals are practical.","d":"Neither of the two proposal are practical.","ans":"B","e":"*Neither* is singular, so it requires a singular verb. However, the noun following *of the two* remains plural."},
{"t":"Sentence Correction","q":"Scarcely _____ the announcement made when objections arose.","a":"had","b":"has","c":"were","d":"was","ans":"D","e":"The complete structure is *Scarcely was the announcement made when...*. Such inversion patterns are frequently tested."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"She sings best than any girl in the choir.","b":"She sings better than any girl in the choir.","c":"She sings more better than any other girl.","d":"She sings better than any other girl in the choir.","ans":"D","e":"Since she herself belongs to the choir, comparison should be with *any other girl*, not *any girl*."},
{"t":"Sentence Correction","q":"The proposal requires that each applicant _____ proof of identity.","a":"submitted","b":"submits","c":"submit","d":"submitting","ans":"C","e":"After expressions such as *requires that*, *demands that*, and *recommends that*, the subjunctive form (*submit*) is used."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"The number of errors has increased.","b":"The number of errors were increasing.","c":"The number of errors have increased.","d":"The number of errors are increasing.","ans":"A","e":"*The number of* is singular and therefore takes *has*, regardless of the plural noun that follows."},
{"t":"Sentence Correction","q":"He has no option but _____ the decision.","a":"accepted","b":"accept","c":"accepting","d":"to accept","ans":"D","e":"The expression *have no option but to + verb* is the standard and most formal construction."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"One should kept one's promises.","b":"One should keeps his promises.","c":"One should keep their promises.","d":"One should keep one's promises.","ans":"D","e":"In formal grammar, *one* is paired with *one's*. Competitive examinations frequently test this agreement pattern."},
{"t":"Sentence Correction","q":"Not only _____ the proposal rejected, but it was also criticized.","a":"has","b":"were","c":"had","d":"was","ans":"D","e":"When *not only* begins a clause, inversion occurs. Since *proposal* is singular, *was* is correct."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"This is the most unique opportunity.","b":"This is a unique opportunity.","c":"This is very uniquely opportunity.","d":"This is more unique opportunity.","ans":"B","e":"*Unique* already means one of a kind. Using *most unique* or *more unique* is generally considered incorrect in formal grammar."},
{"t":"Subject-Verb Agreement","q":"The manager as well as the employees _____ informed about the change.","a":"have been","b":"were","c":"are","d":"was","ans":"D","e":"With *as well as*, the verb agrees with the first subject (*manager*), not the noun following the phrase."},
{"t":"Modifiers & Comparisons","q":"Which sentence is grammatically correct?","a":"Harder you work, the luckier you become.","b":"The harder you work, the luckier you become.","c":"Harder you work, luckier you become.","d":"The harder you work, luckier you become.","ans":"B","e":"Comparative correlative structures require *the* before both comparative forms: *the harder..., the luckier...*."},
{"t":"Conditionals","q":"If he _____ more attentive, he would notice the mistake.","a":"is","b":"had been","c":"were","d":"was","ans":"C","e":"In formal English, hypothetical present situations use *were* for all subjects in second conditional sentences."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"Every student has a notebook.","b":"Every student has a pen.","c":"Every student has an identity card.","d":"Every student has their notebook.","ans":"D","e":"In strict formal grammar, *every student* is singular and traditionally takes *his or her*, not *their*."},
{"t":"Sentence Correction","q":"He is known _____ his honesty and professionalism.","a":"with","b":"from","c":"for","d":"by","ans":"C","e":"We say *known for a quality*, *known by name*, and *known to someone*. Such distinctions are commonly tested."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The audience were clapping their hands.","b":"Neither is correct.","c":"The audience was clapping their hands.","d":"Both can be correct depending on meaning.","ans":"D","e":"Collective nouns may take singular or plural verbs depending on whether the group is viewed as a unit or as individuals."},
{"t":"Sentence Correction","q":"Hardly ever _____ a candidate answer every question correctly.","a":"do","b":"did","c":"does","d":"has","ans":"C","e":"Since the subject *candidate* is singular, inversion requires *does* rather than *do*."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"He prevented me from entering the room.","b":"He prevented me entering from the room.","c":"He prevented me enter the room.","d":"He prevented me to enter the room.","ans":"A","e":"The standard structure is *prevent someone from doing something*. This pattern appears frequently in grammar questions."},
{"t":"Sentence Correction","q":"The report was so detailed _____ it answered every question.","a":"as","b":"which","c":"than","d":"that","ans":"D","e":"The correct construction is *so...that*, used to show result or consequence."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Neither is accepted.","b":"The data have been analyzed carefully.","c":"Both are accepted in modern usage.","d":"The data has been analyzed carefully.","ans":"C","e":"Traditionally, *data* is plural, but modern English increasingly treats it as singular. Both forms are widely accepted today."},
{"t":"Sentence Correction","q":"It is essential that every document _____ before submission.","a":"checked","b":"was checked","c":"is checked","d":"be checked","ans":"D","e":"After expressions such as *it is essential that*, the subjunctive form (*be checked*) is preferred."},
{"t":"Relative Pronouns","q":"Which sentence is correct?","a":"She is one of those people who enjoy reading.","b":"She is one of those people who enjoys reading.","c":"She is one of those people who enjoying reading.","d":"She is one of those person who enjoy reading.","ans":"A","e":"The relative clause refers to *people* (plural), so the verb inside the clause should also be plural."},
{"t":"Sentence Correction","q":"Little _____ about the new policy before its implementation.","a":"have known","b":"had knew","c":"were known","d":"was known","ans":"D","e":"*Little* here means *not much*. The singular verb *was* correctly agrees with the implied singular idea."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"He never scarcely visits the office.","b":"He scarcely visits the office.","c":"He scarcely never visits the office.","d":"He scarcely not visits the office.","ans":"B","e":"Avoid double negatives. *Scarcely* already carries a negative meaning, so adding *never* makes the sentence incorrect."},
{"t":"Modifiers & Comparisons","q":"The sooner the issue is addressed, _____ the outcome will be.","a":"best","b":"good","c":"the better","d":"better","ans":"C","e":"Comparative correlative structures require *the + comparative* in both clauses."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"Many a student have failed this test.","b":"Many a student has failed this test.","c":"Many a students has failed this test.","d":"Many a students have failed this test.","ans":"B","e":"Although *many a* suggests plurality in meaning, it takes a singular noun and a singular verb."},
{"t":"Conditionals","q":"Had the instructions been followed correctly, the complications _____ avoided.","a":"can be","b":"can have been","c":"could have been","d":"could be","ans":"C","e":"This is a past unreal conditional. The correct structure is *could have been avoided*, expressing a possible past result that did not occur. # **English Grammar Usage MCQs (301–330)**"},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"The captain, along with the players, are attending the ceremony.","b":"The captain, along with the players, is attending the ceremony.","c":"The captain, along with the players, were attending the ceremony.","d":"The captain, along with the players, have attended the ceremony.","ans":"B","e":"Expressions such as *along with*, *together with*, and *as well as* do not affect subject-verb agreement. The verb agrees with the main subject (*captain*), which is singular."},
{"t":"Conditionals","q":"He would have succeeded if he _____ more persistent.","a":"were","b":"was","c":"had been","d":"has been","ans":"C","e":"This is a third conditional sentence referring to an unreal past event. The if-clause requires *had been*, while the result clause uses *would have succeeded*."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"The staff is discussing among themselves.","b":"The staff is meeting today.","c":"The staff has decided to postpone the event.","d":"The staff are discussing among themselves.","ans":"A","e":"*Staff* is singular in the first part of the sentence, but *themselves* is plural. The sentence mixes singular and plural reference, making it inconsistent."},
{"t":"Sentence Correction","q":"No sooner _____ the bell rung than the students left the room.","a":"did","b":"has","c":"was","d":"had","ans":"D","e":"The correct structure is *No sooner had...than*. This fixed inversion pattern is a classic grammar-testing favorite."},
{"t":"Prepositions","q":"Which sentence is grammatically correct?","a":"He is addicted to gambling.","b":"He is addicted in gambling.","c":"He is addicted with gambling.","d":"He is addicted for gambling.","ans":"A","e":"The adjective *addicted* is followed by the preposition *to*. When a verb follows, it takes the gerund form."},
{"t":"Sentence Correction","q":"The committee _____ unable to agree on a common solution.","a":"was","b":"is","c":"has","d":"were","ans":"D","e":"Here the committee members are acting individually and disagreeing. Therefore, the collective noun may take a plural verb."},
{"t":"Modifiers & Comparisons","q":"Which sentence is correct?","a":"The fewer mistakes you make, the better your score.","b":"The less mistakes you make, the better your score.","c":"The fewer mistakes you make, better your score.","d":"Fewer mistakes you make, the better your score.","ans":"A","e":"*Mistakes* is a countable noun, so *fewer* is required. The comparative correlative structure also requires *the...the*."},
{"t":"Gerunds & Infinitives","q":"He denied _____ the confidential file.","a":"stealing","b":"to steal","c":"having stole","d":"stole","ans":"A","e":"The verb *deny* is followed by a gerund (*-ing* form). This rule is frequently tested in grammar questions."},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Every member of team have arrived.","b":"Every member of the teams have arrived.","c":"Every members of the teams has arrived.","d":"Every member of the teams has arrived.","ans":"D","e":"The subject is *every member*, which is singular. Therefore, the verb must also be singular."},
{"t":"Pronouns","q":"Which sentence contains no error?","a":"She is one of the scientists who has received the award.","b":"She is one of the scientist who have received the award.","c":"She is one of the scientists who have received the award.","d":"She is one of the scientists who receiving the award.","ans":"C","e":"The relative pronoun *who* refers to *scientists* (plural), so the verb inside the relative clause should be plural."},
{"t":"Subject-Verb Agreement","q":"It is imperative that every applicant _____ the required documents.","a":"submitting","b":"submit","c":"submits","d":"submitted","ans":"B","e":"After expressions such as *it is imperative that*, the subjunctive form is used. The base verb remains unchanged regardless of the subject."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"She has been here for three hours.","b":"She has been here during three hours.","c":"She has been here since three hours.","d":"She has been here from three hours.","ans":"A","e":"*For* is used with a duration of time, while *since* is used with a specific starting point."},
{"t":"Subject-Verb Agreement","q":"Not only the students but also the principal _____ concerned about the issue.","a":"were","b":"are","c":"have been","d":"was","ans":"D","e":"With *not only...but also*, the verb agrees with the nearest subject. Here, *principal* is singular."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"He is different than his brother.","b":"He is different to his brother.","c":"He is different with his brother.","d":"He is different from his brother.","ans":"D","e":"In standard formal English, the preferred expression is *different from*."},
{"t":"Sentence Correction","q":"Little _____ about the consequences at that time.","a":"had understood","b":"have understood","c":"were understood","d":"was understood","ans":"D","e":"*Little* here means *not much*. The sentence refers to a singular idea and therefore takes a singular verb."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"The criterion was reasonable.","b":"The criteria are reasonable.","c":"The criteria is reasonable.","d":"The criterion is reasonable.","ans":"C","e":"*Criteria* is plural and should take a plural verb. The singular form is *criterion*."},
{"t":"Prepositions","q":"He was accused _____ violating departmental rules.","a":"for","b":"with","c":"by","d":"of","ans":"D","e":"The correct construction is *accused of doing something*. This collocation appears frequently in competitive exams."},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Neither Ahmed nor his friends were present.","b":"Neither Ahmed nor his friends was present.","c":"Neither Ahmed nor his friends is present.","d":"Neither Ahmed nor his friends has been present.","ans":"A","e":"In *neither...nor* constructions, the verb agrees with the nearest subject. Since *friends* is plural, *were* is correct."},
{"t":"Conditionals","q":"Had the proposal been approved, it _____ substantial benefits.","a":"brought","b":"brings","c":"would have brought","d":"would bring","ans":"C","e":"This is a third conditional sentence referring to an unreal past result. The correct structure is *would have + past participle*."},
{"t":"Pronouns","q":"Which sentence is correct?","a":"One should respect one's elders.","b":"One should respects one's elders.","c":"One should respected one's elders.","d":"One should respect their elders.","ans":"A","e":"In formal grammar, the pronoun *one* is paired with *one's* to maintain consistency."},
{"t":"Sentence Correction","q":"Seldom _____ such a comprehensive report submitted on time.","a":"are","b":"was","c":"were","d":"is","ans":"D","e":"After *seldom* at the beginning, inversion occurs. The subject *report* is singular, requiring *is*."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The majority of students has voted.","b":"The majority have votes.","c":"The majority of the students has voted.","d":"The majority of the students have voted.","ans":"D","e":"When *majority* refers to individual members of a group, a plural verb is commonly used."},
{"t":"Prepositions","q":"He succeeded _____ convincing the board members.","a":"at","b":"on","c":"in","d":"with","ans":"C","e":"The correct structure is *succeed in doing something*. This is a frequently tested prepositional pattern."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"Many people attended the seminar.","b":"Many person attended the seminar.","c":"Much persons attended the seminar.","d":"Much people attended the seminar.","ans":"A","e":"*People* is a countable plural noun and therefore requires *many*, not *much*."},
{"t":"Sentence Correction","q":"It is desirable that the matter _____ resolved without delay.","a":"being","b":"be","c":"is","d":"was","ans":"B","e":"Expressions such as *it is desirable that* take the subjunctive form. The correct structure is *be resolved*."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"He hardly ever makes mistakes.","b":"He never hardly makes mistakes.","c":"He hardly never makes mistakes.","d":"He hardly not makes mistakes.","ans":"A","e":"*Hardly ever* is a standard expression meaning *rarely*. Double negatives such as *hardly never* are incorrect."},
{"t":"Modifiers & Comparisons","q":"The more frequently you revise, _____ your retention becomes.","a":"the strongest","b":"the stronger","c":"stronger","d":"strongest","ans":"B","e":"Comparative correlative structures require *the + comparative* in both parts of the sentence."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"Both A and B may be correct depending on meaning.","b":"The audience was divided in its opinion.","c":"The audience were divided in their opinions.","d":"Neither A nor B is correct.","ans":"A","e":"Collective nouns can take either singular or plural agreement depending on whether the group is viewed as a unit or as individuals."},
{"t":"Conditionals","q":"Were the government to introduce the reform, it _____ significant administrative changes.","a":"would cause","b":"had caused","c":"caused","d":"causes","ans":"A","e":"*Were + subject + infinitive* is an inverted conditional structure equivalent to *If the government were to introduce the reform*. The result clause takes *would + base verb*. # **English Grammar Usage MCQs (331–360)**"},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Every one of the recommendations has been accepted.","b":"Every one of the recommendations have been accepted.","c":"Every one of the recommendations are accepted.","d":"Every one of the recommendations were accepted.","ans":"A","e":"The subject is *every one*, which is singular. A useful exam rule is to ignore the plural noun after *of* and identify the true subject before choosing the verb."},
{"t":"Prepositions","q":"He is diligent _____ his duties.","a":"on","b":"in","c":"with","d":"at","ans":"B","e":"The standard expression is *diligent in one's duties*. Similar adjective-preposition combinations are frequently tested because they rely on usage rather than logic."},
{"t":"Conditionals","q":"If the instructions had been clearer, fewer mistakes _____.","a":"occur","b":"had occurred","c":"would have occurred","d":"would occur","ans":"C","e":"This is a third conditional sentence. The condition was unreal in the past, so the result clause requires *would have + past participle*."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"The information is confidential.","b":"The advice was useful.","c":"The machinery is expensive.","d":"The equipment are modern.","ans":"D","e":"*Equipment* is an uncountable noun and takes a singular verb. Many competitive exams repeatedly test uncountable nouns such as equipment, luggage, furniture, advice, and information."},
{"t":"Tenses","q":"She insisted that he _____ immediately.","a":"apologizes","b":"apologizing","c":"apologize","d":"apologized","ans":"C","e":"After verbs such as *insist, demand, recommend,* and *suggest*, formal English uses the subjunctive form (*apologize*), not the regular present tense."},
{"t":"Subject-Verb Agreement","q":"Rarely _____ such enthusiasm among newly recruited employees.","a":"observed we","b":"we observe","c":"do we observe","d":"we observed","ans":"C","e":"When restrictive adverbs like *rarely, seldom,* or *never* begin a sentence, inversion occurs. The auxiliary verb comes before the subject."},
{"t":"Pronouns","q":"Which sentence is grammatically correct?","a":"She is one of the candidate who have been selected.","b":"She is one of the candidates who has been selected.","c":"She is one of the candidates who being selected.","d":"She is one of the candidates who have been selected.","ans":"D","e":"The relative pronoun *who* refers to *candidates* (plural), so the verb inside the relative clause must be plural."},
{"t":"Prepositions","q":"He is accustomed _____ criticism.","a":"with","b":"for","c":"to","d":"by","ans":"C","e":"The correct expression is *accustomed to*. Remember that *to* here is a preposition, so any following verb must be in the *-ing* form."},
{"t":"Tenses","q":"By the time the meeting starts, the chairman _____ the agenda.","a":"reviewed","b":"will have reviewed","c":"will review","d":"reviews","ans":"B","e":"The future perfect is used for an action that will be completed before another future event."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"Neither is correct.","b":"The audience was cheering loudly.","c":"The audience were cheering loudly.","d":"Both may be correct depending on meaning.","ans":"D","e":"Collective nouns may take singular or plural agreement depending on whether the group is viewed as one unit or as individual members."},
{"t":"Gerunds & Infinitives","q":"He objected _____ the proposal on legal grounds.","a":"with","b":"against","c":"by","d":"to","ans":"D","e":"The verb *object* is followed by *to*. This remains true whether the object is a noun or a gerund."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"Neither of the plans seems feasible.","b":"Neither of the plans are feasible.","c":"Neither of the plan seems feasible.","d":"Neither of the plans seem feasible.","ans":"A","e":"*Neither* is singular and therefore takes *seems*. The noun after *of* remains plural."},
{"t":"Conditionals","q":"Were the company to expand internationally, it _____ new challenges.","a":"faces","b":"had faced","c":"faced","d":"would face","ans":"D","e":"*Were + subject + infinitive* is an inverted conditional equivalent to *If the company were to expand*."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The reason of the delay is unclear.","b":"The reason to the delay is unclear.","c":"The reason for the delay is unclear.","d":"The reason with the delay is unclear.","ans":"C","e":"The idiomatic expression is *reason for*. Such fixed combinations are often tested because they cannot always be deduced from rules."},
{"t":"Sentence Correction","q":"Hardly had the speech concluded _____ questions began to pour in.","a":"that","b":"when","c":"than","d":"then","ans":"B","e":"The correct structure is *Hardly...when*. Examiners frequently test these paired conjunction patterns."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"Every teacher and student are expected to attend.","b":"Every teacher and student were expected to attend.","c":"Every teacher and student is expected to attend.","d":"Every teacher and student have attended.","ans":"C","e":"When singular nouns are joined by *and* and preceded by *every*, the verb remains singular."},
{"t":"Prepositions","q":"He was praised _____ his dedication and honesty.","a":"at","b":"on","c":"for","d":"with","ans":"C","e":"We praise someone *for* an achievement, quality, or action. This is a common collocation tested in usage questions."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"Much effort has been invested.","b":"Much progress has been made.","c":"Much improvements have been suggested.","d":"Many improvements have been suggested.","ans":"C","e":"*Improvements* is countable and plural, so it requires *many*, not *much*."},
{"t":"Sentence Correction","q":"It is essential that every witness _____ available for questioning.","a":"was","b":"be","c":"is","d":"being","ans":"B","e":"Expressions such as *it is essential that*, *it is necessary that*, and *it is important that* commonly take the subjunctive form."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The number of applications were increasing.","b":"The number of applications has increased.","c":"The number of applications are increasing.","d":"The number of applications have increased.","ans":"B","e":"*The number of* is singular and always takes a singular verb. This rule is repeatedly tested in competitive examinations."},
{"t":"Sentence Correction","q":"Seldom _____ a policy generate such widespread debate.","a":"does","b":"has","c":"did","d":"do","ans":"A","e":"Since the subject *policy* is singular, inversion requires *does*. Always check the actual subject after an inverted opening."},
{"t":"Parallel Structure","q":"Which sentence is correct?","a":"He prefers walking than driving.","b":"He prefers walk to drive.","c":"He prefers walking to driving.","d":"He prefers walking over to driving.","ans":"C","e":"The standard structure is *prefer A to B*. Both elements should be grammatically parallel."},
{"t":"Conditionals","q":"Had she been informed earlier, she _____ the misunderstanding.","a":"avoided","b":"avoids","c":"would avoid","d":"would have avoided","ans":"D","e":"This is a classic third conditional sentence expressing an unreal past result."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"One of my colleague has resigned.","b":"One of my colleagues were resigned.","c":"One of my colleagues has resigned.","d":"One of my colleagues have resigned.","ans":"C","e":"After *one of*, the noun should be plural, but the verb agrees with *one* and remains singular."},
{"t":"Prepositions","q":"He refrained _____ commenting on the matter publicly.","a":"with","b":"from","c":"by","d":"in","ans":"B","e":"The correct expression is *refrain from doing something*. This collocation appears regularly in grammar tests."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The data are convincing.","b":"Both can be accepted depending on style.","c":"Neither is acceptable.","d":"The data is convincing.","ans":"B","e":"Traditional grammar treats *data* as plural, while modern usage often treats it as singular. Candidates should be aware of both conventions."},
{"t":"Sentence Correction","q":"Not until the audit was completed _____ the discrepancy discovered.","a":"has","b":"had","c":"were","d":"was","ans":"D","e":"Opening with *Not until* triggers inversion. Since *discrepancy* is singular, *was* is required."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"He hardly attends meetings.","b":"He never hardly attends meetings.","c":"He hardly not attends meetings.","d":"He hardly never attends meetings.","ans":"A","e":"*Hardly* already carries a negative sense. Combining it with another negative creates an incorrect double negative."},
{"t":"Modifiers & Comparisons","q":"The more carefully the contract is reviewed, _____ the risk of future disputes.","a":"lower","b":"the lower","c":"the lowest","d":"lowest","ans":"B","e":"Comparative correlative structures require *the + comparative* in both clauses. This pattern is highly testable."},
{"t":"Conditionals","q":"Which sentence is grammatically correct?","a":"The manager as well as the supervisors are consulted.","b":"The manager as well as the supervisors have been consulted.","c":"The manager as well as the supervisors was consulted.","d":"The manager as well as the supervisors were consulted.","ans":"C","e":"Phrases such as *as well as* do not alter subject-verb agreement. The verb agrees with the first subject, *manager*, which is singular. # **English Grammar Usage MCQs (361–380)** *Ultra High-Yield Set — Focused on grammar rules that are disproportionately tested in competitive examinations: agreement traps, inversion, conditionals, modifiers, pronouns, parallelism, and error detection.*"},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"Each of the candidates has submitted an application.","b":"Every candidate has submitted an application.","c":"Each of the candidates have submitted an application.","d":"Each candidate has submitted an application.","ans":"C","e":"*Each* is always singular and requires a singular verb. One of the most common examination traps is placing a plural noun (*candidates*) close to the verb to distract the candidate."},
{"t":"Sentence Correction","q":"No sooner had the minister arrived _____ the meeting commenced.","a":"when","b":"than","c":"that","d":"then","ans":"B","e":"The fixed construction is *No sooner...than*. Examiners repeatedly test this alongside *Hardly...when* and *Scarcely...when*."},
{"t":"Relative Pronouns","q":"Which sentence is grammatically correct?","a":"One of the boys who were absent has returned.","b":"One of the boys who were absent have returned.","c":"One of the boys who was absent has returned.","d":"One of the boys who was absent have returned.","ans":"A","e":"The relative clause refers to *boys* (plural), so *were absent* is correct. The main verb agrees with *one* and therefore takes *has*."},
{"t":"Conditionals","q":"If I _____ you, I would reconsider the proposal.","a":"was","b":"had been","c":"were","d":"am","ans":"C","e":"In formal English, hypothetical present situations use *were* for all subjects. This rule is tested far more often than ordinary conditional forms."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"The furniture were delivered yesterday.","b":"The furniture was delivered yesterday.","c":"The furnitures was delivered yesterday.","d":"The furnitures were delivered yesterday.","ans":"B","e":"*Furniture* is an uncountable noun. It has no standard plural form and takes a singular verb."},
{"t":"Sentence Correction","q":"Rarely _____ such a significant policy change implemented so quickly.","a":"was","b":"are","c":"is","d":"were","ans":"C","e":"After *rarely* at the beginning of a sentence, inversion occurs. Since *policy change* is singular, *is* is grammatically correct."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The number of students has increased.","b":"The number of students have increased.","c":"The number of students were increasing.","d":"The number of students are increasing.","ans":"A","e":"*The number of* is singular and always takes a singular verb. In contrast, *a number of* takes a plural verb."},
{"t":"Prepositions","q":"He insisted _____ paying the bill himself.","a":"for","b":"with","c":"in","d":"on","ans":"D","e":"The correct expression is *insist on doing something*. This prepositional pattern appears regularly in grammar papers."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"Neither of the plans is practical.","b":"Neither of the plans are practical.","c":"Neither plan is practical.","d":"Neither proposal is acceptable.","ans":"B","e":"*Neither* is singular and therefore requires a singular verb. This remains true even when followed by a plural noun."},
{"t":"Conditionals","q":"Had the recommendations been implemented earlier, the crisis _____.","a":"may be avoided","b":"could be avoided","c":"was avoided","d":"could have been avoided","ans":"D","e":"This is a past unreal conditional. The correct structure is *could have been avoided*, expressing a possibility that did not occur."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The committee have disagreed among themselves.","b":"The committee is disagreeing among themselves.","c":"The committee has disagreed among itself.","d":"The committee has disagreed among themselves.","ans":"A","e":"Since the members are acting individually and disagreeing, the collective noun is treated as plural."},
{"t":"Sentence Correction","q":"It is essential that every applicant _____ the original documents.","a":"submits","b":"submit","c":"submitted","d":"submitting","ans":"B","e":"Expressions such as *it is essential that*, *it is important that*, and *it is necessary that* take the subjunctive form."},
{"t":"Sentence Correction","q":"Which sentence is correct?","a":"He is superior from his colleagues.","b":"He is superior to his colleagues.","c":"He is superior over his colleagues.","d":"He is superior than his colleagues.","ans":"B","e":"Adjectives such as *superior, inferior, senior,* and *junior* are followed by *to*, never *than*."},
{"t":"Sentence Correction","q":"Not until the final report was released _____ the extent of the problem understood.","a":"was","b":"has","c":"had","d":"were","ans":"A","e":"Opening with *Not until* requires inversion. The subject *extent* is singular, so *was* is required."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"Many a student have failed the examination.","b":"Many a students has failed the examination.","c":"Many a student has failed the examination.","d":"Many a students have failed the examination.","ans":"C","e":"*Many a* takes a singular noun and a singular verb despite referring to multiple individuals."},
{"t":"Modifiers & Comparisons","q":"The more experience a person gains, _____ decision-making becomes.","a":"better","b":"the better","c":"best","d":"the best","ans":"B","e":"Comparative correlative structures always follow the pattern *the more..., the better...*."},
{"t":"Pronouns","q":"Which sentence is grammatically correct?","a":"One should respected one's commitments.","b":"One should respect their commitments.","c":"One should respect one's commitments.","d":"One should respects one's commitments.","ans":"C","e":"In formal grammar, *one* should be paired with *one's* to maintain pronoun consistency."},
{"t":"Sentence Correction","q":"Scarcely had the announcement been made _____ criticism emerged from various quarters.","a":"when","b":"than","c":"then","d":"that","ans":"A","e":"The fixed structure is *Scarcely...when*. It is one of the most repeatedly examined inversion patterns."},
{"t":"Conditionals","q":"Were the economy to improve substantially, unemployment _____.","a":"decreases","b":"would decrease","c":"decreased","d":"had decreased","ans":"B","e":"*Were + subject + infinitive* is an inverted conditional structure equivalent to *If the economy were to improve*. The result clause takes *would + base verb*. # **English Grammar Usage MCQs (381–400)** *Elite High-Yield Set — Focused on the grammar rules most likely to separate high scorers from average candidates. These questions emphasize subtle agreement rules, pronoun reference, parallelism, modifiers, subjunctive mood, and advanced sentence correction.*"},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"More than one candidates have withdrawn the application.","b":"More than one candidate have withdrawn the application.","c":"More than one candidates has withdrawn the application.","d":"More than one candidate has withdrawn the application.","ans":"D","e":"Although *more than one* suggests plurality in meaning, it is followed by a singular noun and singular verb. This is a classic examination trap."},
{"t":"Subject-Verb Agreement","q":"Which sentence contains an error?","a":"Every member of the team was present.","b":"Every member of the teams were present.","c":"Every member was present.","d":"Every member of the teams was present.","ans":"B","e":"The subject is *every member*, which is singular. Regardless of the plural noun that follows, the verb must remain singular."},
{"t":"Modifiers & Comparisons","q":"Had it not been for your assistance, I _____ the task.","a":"could not have completed","b":"could not complete","c":"cannot complete","d":"had not completed","ans":"A","e":"*Had it not been for* introduces an unreal past condition. The result clause requires *could not have + past participle*."},
{"t":"Subject-Verb Agreement","q":"Which sentence is grammatically correct?","a":"Neither the principal nor the teachers are attending.","b":"Neither the principal nor the teachers has attended.","c":"Neither the principal nor the teachers was attending.","d":"Neither the principal nor the teachers is attending.","ans":"A","e":"In *neither...nor* constructions, the verb agrees with the subject nearest to it. Since *teachers* is plural, the verb must be plural."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"The proceeds of the event has been donated to charity.","b":"The proceeds of the event is donated to charity.","c":"The proceeds of the event were donated to charity.","d":"The proceeds of the event was donated to charity.","ans":"C","e":"*Proceeds* is one of the nouns that is plural in form and takes a plural verb. Candidates often mistake it for a singular collective noun."},
{"t":"Sentence Correction","q":"Little _____ about the proposal before the official announcement.","a":"was known","b":"have known","c":"were known","d":"had knew","ans":"A","e":"*Little* here means *not much*. The sentence refers to a singular idea and therefore requires a singular verb."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"The manager demanded that the employee apologized.","b":"The manager demanded that the employee apologizing.","c":"The manager demanded that the employee apologize.","d":"The manager demanded that the employee apologizes.","ans":"C","e":"After verbs such as *demand, insist, recommend,* and *propose*, the subjunctive form is used. The verb remains in its base form."},
{"t":"Pronouns","q":"Which sentence is correct?","a":"He is one of the authors who has contributed to the book.","b":"He is one of the author who have contributed to the book.","c":"He is one of the authors who contributing to the book.","d":"He is one of the authors who have contributed to the book.","ans":"D","e":"The relative pronoun *who* refers to *authors*, which is plural. Therefore, the verb inside the relative clause must also be plural."},
{"t":"Sentence Correction","q":"No sooner had the investigation begun _____ new evidence emerged.","a":"that","b":"when","c":"than","d":"then","ans":"C","e":"The fixed expression is *No sooner...than*. This is one of the most frequently tested inversion patterns."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"The cattle are grazing in the field.","b":"The poultry are kept in a separate enclosure.","c":"The police are investigating the case.","d":"The poultry is kept in a separate enclosure.","ans":"D","e":"In traditional grammar, *poultry* is usually treated as a collective plural noun. Therefore, *are kept* is generally preferred."},
{"t":"Parallel Structure","q":"Which sentence is grammatically correct?","a":"He prefers working late over to arriving early.","b":"He prefers work late to arrive early.","c":"He prefers working late than arriving early.","d":"He prefers working late to arriving early.","ans":"D","e":"The structure *prefer A to B* requires grammatical parallelism. Since *working* is used in the first part, *arriving* should be used in the second."},
{"t":"Conditionals","q":"Were the proposal accepted, it _____ significant reforms.","a":"would bring","b":"had brought","c":"brought","d":"brings","ans":"A","e":"This is an inverted conditional sentence equivalent to *If the proposal were accepted*. The result clause takes *would + base verb*."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"A number of candidates has applied.","b":"A number of candidates have applied.","c":"A number of candidate have applied.","d":"A number of candidates has been applied.","ans":"B","e":"*A number of* takes a plural verb because it refers to several individuals. This rule is commonly tested alongside *the number of*."},
{"t":"Sentence Correction","q":"Not only _____ the evidence convincing, but it was also corroborated by witnesses.","a":"has","b":"had","c":"was","d":"were","ans":"C","e":"When *not only* begins a clause, inversion occurs. Since *evidence* is singular and uncountable, *was* is required."},
{"t":"Sentence Correction","q":"Which sentence is grammatically correct?","a":"Each of the report contains useful information.","b":"Each of the reports contain useful information.","c":"Each of the reports contains useful information.","d":"Each of the reports have contained useful information.","ans":"C","e":"*Each* is singular and therefore requires a singular verb. The noun after *of* remains plural."},
{"t":"Sentence Correction","q":"Which sentence contains an error?","a":"Mathematics is important for engineers.","b":"The news is encouraging.","c":"Measles are a contagious disease.","d":"Physics is a challenging subject.","ans":"C","e":"*Measles* is the name of a disease and is treated as a singular noun. Therefore, *is* should be used instead of *are*."},
{"t":"Modifiers & Comparisons","q":"The more carefully a contract is drafted, _____ the likelihood of future disputes.","a":"the lowest","b":"lower","c":"the lower","d":"lowest","ans":"C","e":"Comparative correlative structures require *the + comparative* in both clauses. This pattern is frequently tested in sentence correction."},
{"t":"Prepositions","q":"Which sentence is grammatically correct?","a":"He was prevented from speaking.","b":"He was prevented to speak.","c":"He was prevented from speak.","d":"He was prevented speaking from.","ans":"A","e":"The standard construction is *prevent someone from doing something*. After the preposition *from*, a gerund is required."},
{"t":"Sentence Correction","q":"Which sentence contains no error?","a":"The faculty is divided in its opinion.","b":"Neither A nor B is correct.","c":"The faculty are divided in their opinions.","d":"Both A and B may be correct depending on meaning.","ans":"D","e":"Collective nouns may take singular or plural agreement depending on whether the group is viewed as a unit or as individual members."},
{"t":"Tenses","q":"It is high time the authorities _____ decisive action.","a":"have taken","b":"taking","c":"take","d":"took","ans":"D","e":"After *It is high time*, English uses the past tense to indicate that an action is overdue and should already have happened. This is a very common advanced grammar question."},
{"t":"Sentence Correction","q":"Each of the doctors _____ a private clinic.","a":"are owning","b":"have","c":"owns","d":"own","ans":"C","e":"After *each of* + plural noun, the verb is singular. *Each* takes a singular verb."},
{"t":"Sentence Correction","q":"The number of patients _____ increasing every year.","a":"is","b":"were","c":"have been","d":"are","ans":"A","e":"*The number of* takes a singular verb; *a number of* takes plural. Here: *is*."},
{"t":"Subject-Verb Agreement","q":"Mathematics _____ my favourite subject.","a":"are","b":"is","c":"have been","d":"were","ans":"B","e":"Subjects ending in *-ics* like *mathematics, physics, economics* take a singular verb."},
{"t":"Sentence Correction","q":"Neither the doctor nor the nurses _____ available.","a":"are","b":"has","c":"is","d":"was","ans":"A","e":"With *neither...nor*, the verb agrees with the noun closer to it (*nurses* → plural)."},
{"t":"Subject-Verb Agreement","q":"A pair of scissors _____ on the table.","a":"is","b":"were","c":"are","d":"have been","ans":"A","e":"*A pair of* takes a singular verb because *pair* is the subject head."},
{"t":"Sentence Correction","q":"Five thousand rupees _____ a fair price for this.","a":"is","b":"have been","c":"are","d":"were","ans":"A","e":"When a sum of money is treated as a single amount, the verb is singular."},
{"t":"Subject-Verb Agreement","q":"Either you or he _____ responsible for the mistake.","a":"have been","b":"are","c":"is","d":"were","ans":"C","e":"With *either...or*, the verb agrees with the nearer subject (*he* → singular)."},
{"t":"Sentence Correction","q":"The committee _____ unable to reach a decision.","a":"were","b":"is","c":"have","d":"are","ans":"B","e":"Collective nouns acting as a unified body take a singular verb."},
{"t":"Sentence Correction","q":"Bread and butter _____ a common breakfast.","a":"are","b":"were","c":"is","d":"have been","ans":"C","e":"When two nouns form a single compound concept, the verb is singular."},
{"t":"Sentence Correction","q":"Many a student _____ failed the exam.","a":"have","b":"has","c":"were","d":"are","ans":"B","e":"*Many a + singular noun* takes a singular verb in formal English."},
{"t":"Sentence Correction","q":"There _____ several reasons for the delay.","a":"are","b":"is","c":"was","d":"has been","ans":"A","e":"With *there + be*, the verb agrees with the noun following it (*reasons* → plural)."},
{"t":"Sentence Correction","q":"The news _____ shocking to everyone.","a":"are","b":"was","c":"were","d":"have been","ans":"B","e":"*News* is uncountable and takes a singular verb."},
{"t":"Sentence Correction","q":"She is _____ honest woman.","a":"a","b":"no article","c":"the","d":"an","ans":"D","e":"Use *an* before a vowel sound. *Honest* begins with a silent *h* (vowel sound)."},
{"t":"Sentence Correction","q":"He plays _____ violin beautifully.","a":"the","b":"no article","c":"an","d":"a","ans":"A","e":"Names of musical instruments take *the* when speaking of playing them."},
{"t":"Articles","q":"_____ Nile is the longest river in Africa.","a":"The","b":"A","c":"No article","d":"An","ans":"A","e":"Names of rivers take the definite article *the*."},
{"t":"Sentence Correction","q":"I want to be _____ engineer when I grow up.","a":"an","b":"the","c":"a","d":"no article","ans":"A","e":"Use *an* before a vowel sound. *Engineer* starts with the vowel sound /e/."},
{"t":"Sentence Correction","q":"She gave me _____ useful piece of advice.","a":"no article","b":"the","c":"a","d":"an","ans":"C","e":"*Useful* starts with the consonant sound /j/ (yoo), so *a* is correct."},
{"t":"Sentence Correction","q":"_____ poor need our support.","a":"An","b":"A","c":"No article","d":"The","ans":"D","e":"*The + adjective* refers to a class of people. *The poor* = poor people in general."},
{"t":"Sentence Correction","q":"He went to _____ Europe last year.","a":"a","b":"an","c":"no article","d":"the","ans":"C","e":"No article before names of continents (Europe, Asia, Africa) and most countries."},
{"t":"Sentence Correction","q":"She is _____ MBA from a reputed university.","a":"a","b":"the","c":"no article","d":"an","ans":"D","e":"*MBA* begins with the vowel sound /e/ (em-bee-ay), so *an* is correct."},
{"t":"Articles","q":"Honesty is _____ best policy.","a":"a","b":"no article","c":"the","d":"an","ans":"C","e":"Superlatives (*best, greatest, most*) take the definite article *the*."},
{"t":"Sentence Correction","q":"_____ sun rises in the east.","a":"The","b":"An","c":"No article","d":"A","ans":"A","e":"Unique objects in nature (the sun, the moon, the earth) take *the*."},
{"t":"Prepositions","q":"She is married _____ a doctor.","a":"for","b":"to","c":"with","d":"by","ans":"B","e":"The standard collocation is *married to* someone."},
{"t":"Prepositions","q":"He is suffering _____ malaria.","a":"by","b":"with","c":"from","d":"of","ans":"C","e":"*Suffer from* is the standard preposition used with illness or hardship."},
{"t":"Sentence Correction","q":"He is afraid _____ dogs.","a":"with","b":"to","c":"from","d":"of","ans":"D","e":"The standard expression is *afraid of* something."},
{"t":"Prepositions","q":"I congratulate you _____ your success.","a":"with","b":"for","c":"on","d":"at","ans":"C","e":"The standard preposition after *congratulate* is *on*."},
{"t":"Prepositions","q":"She is angry _____ me for being late.","a":"with","b":"on","c":"to","d":"against","ans":"A","e":"*Angry with* (a person) is the correct collocation; *angry at* is used for situations."},
{"t":"Gerunds & Infinitives","q":"He insisted _____ paying the bill.","a":"on","b":"for","c":"to","d":"at","ans":"A","e":"*Insist on* + gerund is the correct construction."},
{"t":"Prepositions","q":"The teacher was pleased _____ the students.","a":"with","b":"from","c":"at","d":"on","ans":"A","e":"*Pleased with* + person is the standard collocation."},
{"t":"Sentence Correction","q":"He apologised _____ his rude behaviour.","a":"about","b":"on","c":"for","d":"against","ans":"C","e":"*Apologise for* + offence is the standard form (note: *apologise to* someone)."},
{"t":"Prepositions","q":"She is jealous _____ her sister.","a":"from","b":"of","c":"with","d":"against","ans":"B","e":"The standard collocation is *jealous of* someone."},
{"t":"Sentence Correction","q":"We must abide _____ the law.","a":"with","b":"by","c":"to","d":"on","ans":"B","e":"*Abide by* (rules, decisions, laws) is the fixed expression."},
{"t":"Sentence Correction","q":"He died _____ cholera.","a":"from","b":"by","c":"with","d":"of","ans":"D","e":"*Die of* a disease is standard; *die from* injuries; *die by* a weapon."},
{"t":"Sentence Correction","q":"Compare this _____ that.","a":"with","b":"to","c":"from","d":"against","ans":"A","e":"*Compare with* shows differences; *compare to* shows similarities. Both are accepted."},
{"t":"Voice","q":"The book consists _____ ten chapters.","a":"of","b":"from","c":"with","d":"in","ans":"A","e":"*Consist of* means to be composed of and never takes a passive form."},
{"t":"Prepositions","q":"She is fond _____ chocolates.","a":"with","b":"about","c":"for","d":"of","ans":"D","e":"*Fond of* + noun/gerund is the standard collocation."},
{"t":"Tenses","q":"I _____ here for five years.","a":"lived","b":"live","c":"am living","d":"have been living","ans":"D","e":"Actions that started in the past and continue to the present use *present perfect continuous*."},
{"t":"Tenses","q":"Water _____ at 100 degrees Celsius.","a":"boiled","b":"is boiling","c":"has boiled","d":"boils","ans":"D","e":"General scientific facts use the simple present tense."},
{"t":"Tenses","q":"By the time you arrive, I _____ the report.","a":"will be finishing","b":"will have finished","c":"will finish","d":"finish","ans":"B","e":"*Future perfect* (will have + V3) is used for actions completed before another future event."},
{"t":"Tenses","q":"She _____ in this office since 2020.","a":"worked","b":"has been working","c":"works","d":"is working","ans":"B","e":"For ongoing actions since a starting point, use *present perfect continuous*."},
{"t":"Sentence Correction","q":"When I arrived, they _____ dinner.","a":"were having","b":"had","c":"are having","d":"have","ans":"A","e":"*Past continuous* (were + -ing) describes an action in progress when another past action occurred."},
{"t":"Tenses","q":"I _____ him yesterday.","a":"have met","b":"meet","c":"met","d":"had met","ans":"C","e":"With a specific past time (*yesterday*), the simple past tense is required."},
{"t":"Tenses","q":"She _____ the book before I borrowed it.","a":"has read","b":"was reading","c":"read","d":"had read","ans":"D","e":"*Past perfect* (had + V3) describes an action completed before another past action."},
{"t":"Sentence Correction","q":"The patient _____ the medicine when the doctor arrived.","a":"was taking","b":"has taken","c":"takes","d":"is taking","ans":"A","e":"*Past continuous* shows an action in progress at a specific past moment."},
{"t":"Tenses","q":"He _____ the proposal next week.","a":"discussed","b":"will discuss","c":"discusses","d":"is discussing","ans":"B","e":"*Will + base verb* expresses a future intention or scheduled future action."},
{"t":"Tenses","q":"The sun _____ in the east.","a":"has risen","b":"rose","c":"is rising","d":"rises","ans":"D","e":"Universal truths take the simple present tense."},
{"t":"Sentence Correction","q":"I _____ my homework when the lights went off.","a":"have done","b":"was doing","c":"do","d":"did","ans":"B","e":"*Past continuous* describes the ongoing action interrupted by another past event."},
{"t":"Tenses","q":"She has been ill _____ Monday.","a":"for","b":"by","c":"from","d":"since","ans":"D","e":"*Since* is used with present perfect / present perfect continuous for a starting point."},
{"t":"Conditionals","q":"If it _____ tomorrow, the match will be cancelled.","a":"rained","b":"has rained","c":"will rain","d":"rains","ans":"D","e":"First conditional: *if + present simple*, *will + base verb* (real future possibility)."},
{"t":"Conditionals","q":"If I _____ you, I would accept the offer.","a":"had been","b":"was","c":"am","d":"were","ans":"D","e":"Second conditional: *were* is used for all subjects in unreal present hypotheticals."},
{"t":"Conditionals","q":"If she had studied harder, she _____ the exam.","a":"will pass","b":"had passed","c":"would have passed","d":"would pass","ans":"C","e":"Third conditional: *would have + V3* in the main clause for unreal past situations."},
{"t":"Conditionals","q":"Unless you hurry, you _____ the bus.","a":"miss","b":"will miss","c":"missed","d":"would miss","ans":"B","e":"*Unless* + present simple takes *will + base verb* (similar to first conditional structure)."},
{"t":"Conditionals","q":"Had I known about the meeting, I _____ attended.","a":"would have","b":"would","c":"will have","d":"shall have","ans":"A","e":"Inverted third conditional: *Had I known* = *If I had known*, followed by *would have + V3*."},
{"t":"Conditionals","q":"If you heat ice, it _____.","a":"would melt","b":"melts","c":"melted","d":"will melt","ans":"B","e":"Zero conditional: *if + present*, *present* — for general/scientific truths."},
{"t":"Conditionals","q":"Were he to apply, he _____ get the job.","a":"will","b":"shall","c":"would","d":"had","ans":"C","e":"Inverted second conditional (formal): *Were he to* = *If he were to*; main clause uses *would*."},
{"t":"Sentence Correction","q":"I wish I _____ taller.","a":"were","b":"am","c":"have been","d":"was","ans":"A","e":"After *I wish* (present unreal), *were* is used for all persons in formal English."},
{"t":"Prepositions","q":"The book belongs to _____.","a":"me","b":"my","c":"I","d":"mine","ans":"A","e":"After a preposition, the object pronoun (*me*) is required, not subject pronoun."},
{"t":"Prepositions","q":"Between you and _____, this is confidential.","a":"me","b":"mine","c":"I","d":"myself","ans":"A","e":"After the preposition *between*, the object form *me* is required."},
{"t":"Pronouns","q":"It was _____ who broke the vase.","a":"me","b":"I","c":"myself","d":"mine","ans":"B","e":"In the formal construction *It was + pronoun + who*, the subject form (*I*) is preferred."},
{"t":"Sentence Correction","q":"Everyone should bring _____ own pen.","a":"his or her","b":"theirs","c":"his","d":"their","ans":"A","e":"In formal writing, *his or her* matches the indefinite *everyone*. (Modern usage also accepts *their*.)"},
{"t":"Pronouns","q":"The boy hurt _____ while playing.","a":"him","b":"he","c":"himself","d":"his","ans":"C","e":"When the subject performs an action on itself, the reflexive pronoun is used."},
{"t":"Sentence Correction","q":"Neither of the boys completed _____ work.","a":"them","b":"they","c":"their","d":"his","ans":"D","e":"*Neither* is singular and takes a singular possessive (*his*) in formal English."},
{"t":"Subject-Verb Agreement","q":"I and he _____ classmates.","a":"were","b":"are","c":"was","d":"is","ans":"B","e":"Compound subject with *I and he* refers to two people, taking a plural verb. (Polite order: *he and I*.)"},
{"t":"Prepositions","q":"Whom did you give the keys _____?","a":"with","b":"for","c":"to","d":"from","ans":"C","e":"*Give to* someone; the preposition *to* completes the indirect-object structure."},
{"t":"Modifiers & Comparisons","q":"She is the _____ of the two sisters.","a":"taller","b":"tall","c":"most tall","d":"tallest","ans":"A","e":"When comparing two things, the comparative (*-er*) is used, not the superlative."},
{"t":"Sentence Correction","q":"He is more intelligent than _____.","a":"I","b":"me","c":"mine","d":"myself","ans":"A","e":"In formal usage, the implied verb completes the comparison: *more intelligent than I (am)*."},
{"t":"Modifiers & Comparisons","q":"Running fast, the bus was missed by him. — Which is correct?","a":"Running fast, the bus was missed by him.","b":"Running fast, missing the bus he did.","c":"Running fast, he missed the bus.","d":"He missed the bus running fast.","ans":"C","e":"A participle phrase must modify the subject. *Running fast* modifies *he*, not *the bus*."},
{"t":"Parallel Structure","q":"She likes singing, dancing, and to paint. — Which is the correct version?","a":"singing, dancing, and to paint","b":"singing, to dance, and painting","c":"to sing, dancing, and painting","d":"singing, dancing, and painting","ans":"D","e":"Parallel structure: all three items in the list must be in the same grammatical form."},
{"t":"Relative Pronouns","q":"He gave the book to the boy _____ was sitting in the corner.","a":"whose","b":"whom","c":"who","d":"which","ans":"C","e":"*Who* (subject) refers to a person performing the action of the relative clause."},
{"t":"Pronouns","q":"The man _____ I met yesterday is a surgeon.","a":"whom","b":"who","c":"whose","d":"which","ans":"A","e":"*Whom* is the object form, used when the relative pronoun is the object of the verb."},
{"t":"Modifiers & Comparisons","q":"She speaks English _____.","a":"fluent","b":"more fluent","c":"fluently","d":"most fluent","ans":"C","e":"Adverbs (*fluently*) modify verbs (*speaks*); adjectives modify nouns."},
{"t":"Modifiers & Comparisons","q":"This is the _____ book I have ever read.","a":"interesting","b":"most interesting","c":"much interesting","d":"more interesting","ans":"B","e":"For comparing among three or more, the superlative form (*most interesting*) is used."},
{"t":"Tenses","q":"The letter _____ by Ali yesterday.","a":"has written","b":"is written","c":"wrote","d":"was written","ans":"D","e":"Passive past tense: *was/were + V3*. The subject (*letter*) receives the action."},
{"t":"Voice","q":"English _____ in many countries.","a":"has spoken","b":"is speaking","c":"is spoken","d":"speaks","ans":"C","e":"Universal facts about a passively-received action: *is spoken*."},
{"t":"Prepositions","q":"The book has been read by _____.","a":"with the boy","b":"to the boy","c":"by the boy","d":"the boy","ans":"D","e":"In passive voice, the agent follows *by* directly; here only *the boy* should follow the preposition."},
{"t":"Voice","q":"Active: She is writing a novel. Passive: A novel _____ by her.","a":"has being written","b":"is been written","c":"is wrote","d":"is being written","ans":"D","e":"Present continuous passive: *is/are being + V3*. *is being written* matches *is writing*."},
{"t":"Tenses","q":"Active: They will finish the project. Passive: The project _____ by them.","a":"will finish","b":"will have finished","c":"will be finished","d":"is being finished","ans":"C","e":"Future simple passive: *will be + V3*."},
{"t":"Tenses","q":"Active: Someone has stolen my wallet. Passive: My wallet _____.","a":"has been stolen","b":"has stolen","c":"was being stolen","d":"is stolen","ans":"A","e":"Present perfect passive: *has/have been + V3*."},
{"t":"Gerunds & Infinitives","q":"She suggested _____ the meeting.","a":"postponing","b":"postpone","c":"to postpone","d":"to postponing","ans":"A","e":"After *suggest*, a gerund (*-ing*) is required; *suggest to + infinitive* is incorrect."},
{"t":"Gerunds & Infinitives","q":"He stopped _____ to take a break.","a":"worked","b":"to work","c":"work","d":"working","ans":"B","e":"*Stop + infinitive* = stop in order to do something. *Stop + gerund* = cease the activity."},
{"t":"Prepositions","q":"I look forward _____ from you.","a":"heard","b":"hearing","c":"to hear","d":"to hearing","ans":"D","e":"*Look forward to* takes a gerund (*-ing*); *to* here is a preposition, not part of infinitive."},
{"t":"Gerunds & Infinitives","q":"Would you mind _____ the window?","a":"open","b":"to opening","c":"to open","d":"opening","ans":"D","e":"After *mind*, a gerund is required."},
{"t":"Gerunds & Infinitives","q":"He denied _____ the money.","a":"take","b":"taken","c":"taking","d":"to take","ans":"C","e":"After *deny*, a gerund is required."},
{"t":"Gerunds & Infinitives","q":"They decided _____ the project.","a":"continuing","b":"to continue","c":"continued","d":"continue","ans":"B","e":"After *decide*, an infinitive (*to + base*) is required."},
{"t":"Gerunds & Infinitives","q":"She managed _____ the exam despite being ill.","a":"passing","b":"to pass","c":"pass","d":"passed","ans":"B","e":"After *manage*, an infinitive (*to + base*) is required."},
{"t":"Gerunds & Infinitives","q":"I am used _____ early.","a":"wake up","b":"to wake up","c":"to waking up","d":"waking up","ans":"C","e":"*Used to + gerund* = accustomed to a habit. *Used to + base* = past habit (different meaning)."},
{"t":"Sentence Correction","q":"He prefers tea _____ coffee.","a":"to","b":"from","c":"than","d":"over","ans":"A","e":"*Prefer X to Y* is the standard structure; *than* is incorrect here."},
{"t":"Prepositions","q":"She is good at _____ problems.","a":"solve","b":"solving","c":"to solve","d":"solved","ans":"B","e":"After *good at* (preposition), a gerund is required."},
{"t":"Prepositions","q":"I am looking forward to _____ you next week.","a":"meeting","b":"meet","c":"have met","d":"to meet","ans":"A","e":"After *look forward to* (where *to* is a preposition), a gerund is required."},
{"t":"Gerunds & Infinitives","q":"It is no use _____ over spilt milk.","a":"cried","b":"crying","c":"cry","d":"to cry","ans":"B","e":"After *It is no use* / *no good*, a gerund (*-ing*) is required."},
{"t":"Tenses","q":"He said, \"I am tired.\" → He said that _____ tired.","a":"he was","b":"I was","c":"he is","d":"he has been","ans":"A","e":"In reported speech, present tense shifts to past; pronoun *I* becomes *he*."},
{"t":"Reported Speech","q":"She said, \"I will help you.\" → She said _____ help me.","a":"she will","b":"she had","c":"she would","d":"I would","ans":"C","e":"In reported speech, *will* shifts to *would*; pronouns and time references adjust accordingly."},
{"t":"Tenses","q":"\"Where do you live?\" he asked. → He asked _____.","a":"where I live","b":"where I lived","c":"where did I live","d":"where do I live","ans":"B","e":"Reported wh-questions use statement word-order and the verb shifts back one tense."},
{"t":"Reported Speech","q":"\"Don't be late,\" she told him. → She told him _____ late.","a":"don't be","b":"to not be","c":"not being","d":"not to be","ans":"D","e":"Negative commands in reported speech: *told/asked + not to + base verb*."},
{"t":"Tenses","q":"\"I have finished my work,\" he said. → He said _____ his work.","a":"I have finished","b":"I had finished","c":"he has finished","d":"he had finished","ans":"D","e":"Reported speech: present perfect shifts to past perfect; *I* becomes *he*."},
{"t":"Reported Speech","q":"\"Open the door,\" he ordered. → He ordered me _____ the door.","a":"open","b":"opened","c":"to open","d":"opening","ans":"C","e":"Reported imperatives use *ordered/told/asked + object + to + base verb*."},
{"t":"Sentence Correction","q":"Please look _____ this matter immediately.","a":"up","b":"into","c":"after","d":"over","ans":"B","e":"*Look into* = investigate. *Look after* = take care of. *Look over* = quickly review."},
{"t":"Prepositions","q":"She is very particular _____ punctuality.","a":"in","b":"about","c":"for","d":"of","ans":"B","e":"The standard collocation is *particular about* something."},
{"t":"Sentence Correction","q":"We should not part _____ our principles.","a":"with","b":"from","c":"against","d":"away","ans":"A","e":"*Part with* = give up / let go of (something)."},
{"t":"Sentence Correction","q":"The two boys had a quarrel _____ each other.","a":"to","b":"with","c":"against","d":"on","ans":"B","e":"*Quarrel with* (a person) about (an issue) is the standard structure."},
{"t":"Sentence Correction","q":"His arguments are based _____ solid evidence.","a":"on","b":"in","c":"at","d":"over","ans":"A","e":"*Based on* is the fixed expression."},
{"t":"Prepositions","q":"She is averse _____ smoking.","a":"against","b":"to","c":"from","d":"with","ans":"B","e":"*Averse to* is the correct preposition (strongly disliking)."}
];